    def _execute_storage_transfers(
        self,
        storage_transfers: list[PlannedStorageTransfer],
        *,
        phase_label: str = "Storage transfers",
    ) -> ExecutionPhaseOutcome:
        normalized_transfers = [
            transfer
            for transfer in storage_transfers
            if int(transfer.item_id) > 0 and max(0, int(transfer.quantity)) > 0
        ]
        outcome = ExecutionPhaseOutcome(
            label=phase_label,
            measure_label="items",
            attempted=sum(max(0, int(transfer.quantity)) for transfer in normalized_transfers),
        )
        if not normalized_transfers:
            return outcome

        self._debug_log(
            f"{phase_label}: transfers={len(normalized_transfers)} "
            f"planned_items={sum(max(0, int(transfer.quantity)) for transfer in normalized_transfers)}"
        )
        for transfer in normalized_transfers:
            item_id = int(transfer.item_id)
            quantity = max(0, int(transfer.quantity))
            transfer_label = str(transfer.label or f"Item {item_id}")
            transfer_model_id = max(0, int(getattr(transfer, "model_id", 0)))
            transfer_reason = str(getattr(transfer, "reason", "") or "")
            if quantity <= 0:
                continue

            current_quantity = (
                self._get_inventory_source_stack_quantity(item_id)
                if transfer.direction == STORAGE_TRANSFER_DEPOSIT
                else max(0, int(GLOBAL_CACHE.Item.Properties.GetQuantity(item_id)))
            )
            if current_quantity <= 0:
                self._debug_log(
                    f"{phase_label} transfer skipped: direction={transfer.direction} label={transfer_label} "
                    f"model={transfer_model_id} item_id={item_id} planned={quantity} current=0"
                    + (f" reason={transfer_reason}" if transfer_reason else "")
                )
                outcome.depleted += quantity
                continue
            requested_quantity = min(current_quantity, quantity)
            depleted_quantity = max(0, quantity - current_quantity)
            if requested_quantity <= 0:
                self._debug_log(
                    f"{phase_label} transfer skipped: direction={transfer.direction} label={transfer_label} "
                    f"model={transfer_model_id} item_id={item_id} planned={quantity} move=0"
                    + (f" reason={transfer_reason}" if transfer_reason else "")
                )
                outcome.depleted += quantity
                continue

            self._debug_log(
                f"{phase_label} transfer: direction={transfer.direction} label={transfer_label} "
                f"model={transfer_model_id} item_id={item_id} planned={quantity} current={current_quantity} move={requested_quantity}"
                + (f" reason={transfer_reason}" if transfer_reason else "")
            )

            moved = False
            before_inventory_model_count = 0
            if transfer.direction == STORAGE_TRANSFER_WITHDRAW:
                if transfer_model_id > 0:
                    try:
                        before_inventory_model_count = max(0, int(GLOBAL_CACHE.Inventory.GetModelCount(transfer_model_id)))
                    except Exception:
                        before_inventory_model_count = 0
                moved = bool(GLOBAL_CACHE.Inventory.WithdrawItemFromStorage(item_id, ammount=requested_quantity))
            elif transfer.direction == STORAGE_TRANSFER_DEPOSIT:
                material_storage_result = yield from self._deposit_material_to_storage_first(
                    item_id,
                    requested_quantity,
                    current_quantity=current_quantity,
                    planned_model_id=transfer.model_id,
                )
                if material_storage_result.attempted:
                    if material_storage_result.moved_quantity > 0:
                        outcome.completed += int(material_storage_result.moved_quantity)
                    if material_storage_result.abort_regular_fallback:
                        outcome.timeout_failures += max(
                            0,
                            requested_quantity - max(0, int(material_storage_result.moved_quantity)),
                        )
                        outcome.depleted += depleted_quantity
                        yield from Routines.Yield.wait(60)
                        continue

                    requested_quantity = max(0, int(material_storage_result.remaining_quantity))
                    if requested_quantity <= 0:
                        outcome.depleted += depleted_quantity
                        yield from Routines.Yield.wait(60)
                        continue

                    current_quantity = self._get_inventory_source_stack_quantity(item_id)
                    post_material_depleted_quantity = max(0, requested_quantity - current_quantity)
                    requested_quantity = min(requested_quantity, current_quantity)
                    if requested_quantity <= 0:
                        outcome.depleted += depleted_quantity + post_material_depleted_quantity
                        yield from Routines.Yield.wait(60)
                        continue
                    depleted_quantity += post_material_depleted_quantity

                moved = bool(GLOBAL_CACHE.Inventory.DepositItemToStorage(item_id, ammount=requested_quantity))

            if not moved:
                self._debug_log(
                    f"{phase_label} transfer queued-noop: direction={transfer.direction} label={transfer_label} "
                    f"model={transfer_model_id} item_id={item_id} requested={requested_quantity}"
                    + (f" reason={transfer_reason}" if transfer_reason else "")
                )
                outcome.timeout_failures += requested_quantity
                outcome.depleted += depleted_quantity
                continue

            queue_cleared = yield from self._wait_for_action_queue_empty("ACTION", timeout_ms=2000, step_ms=50)
            final_quantity = (
                self._get_inventory_source_stack_quantity(item_id)
                if transfer.direction == STORAGE_TRANSFER_DEPOSIT
                else max(0, int(GLOBAL_CACHE.Item.Properties.GetQuantity(item_id)))
            )
            moved_quantity = 0
            if transfer.direction == STORAGE_TRANSFER_WITHDRAW and transfer_model_id > 0:
                final_inventory_model_count = yield from self._wait_for_inventory_model_count_at_least(
                    transfer_model_id,
                    before_inventory_model_count + requested_quantity,
                    timeout_ms=2000 if queue_cleared else 1000,
                    step_ms=50,
                )
                moved_quantity = max(0, int(final_inventory_model_count) - before_inventory_model_count)
            elif transfer.direction == STORAGE_TRANSFER_DEPOSIT and queue_cleared:
                expected_quantity = max(0, current_quantity - requested_quantity)
                final_quantity = yield from self._wait_for_inventory_source_stack_quantity_target(
                    item_id,
                    expected_quantity,
                    timeout_ms=2000,
                    step_ms=50,
                )
            elif queue_cleared:
                expected_quantity = max(0, current_quantity - requested_quantity)
                final_quantity = yield from self._wait_for_stack_quantity_target(
                    item_id,
                    expected_quantity,
                    timeout_ms=2000,
                    step_ms=50,
                )

            if moved_quantity <= 0:
                moved_quantity = max(0, current_quantity - max(0, int(final_quantity)))
            if moved_quantity > 0:
                outcome.completed += moved_quantity
            shortfall = max(0, requested_quantity - moved_quantity)
            if shortfall > 0:
                outcome.timeout_failures += shortfall
            outcome.depleted += depleted_quantity
            self._debug_log(
                f"{phase_label} transfer result: direction={transfer.direction} label={transfer_label} "
                f"model={transfer_model_id} item_id={item_id} moved={moved_quantity} shortfall={shortfall} "
                f"final={max(0, int(final_quantity))}"
                + (f" reason={transfer_reason}" if transfer_reason else "")
            )
            yield from Routines.Yield.wait(60)

        self._debug_log(
            f"{phase_label}: completed={outcome.completed}/{outcome.attempted} "
            f"timeouts={outcome.timeout_failures} depleted={outcome.depleted}"
        )
        return outcome

    def _buy_planned_rune_trader_items(
        self,
        coords: tuple[float, float],
        rune_buys: list[PlannedTraderBuy],
        *,
        phase_label: str = "Rune trader buys",
        trader_items: list[int] | None = None,
    ) -> ExecutionPhaseOutcome:
        outcome = ExecutionPhaseOutcome(
            label=phase_label,
            measure_label="items",
            attempted=sum(max(0, int(planned_buy.quantity)) for planned_buy in rune_buys),
        )
        if not rune_buys:
            return outcome

        self._debug_log(
            f"{phase_label}: coords={self._format_debug_coords(coords)} "
            f"planned_targets={len(rune_buys)} planned_items={outcome.attempted}"
        )
        using_existing_trader_items = trader_items is not None
        if trader_items is None:
            x, y = coords
            trader_items = yield from Routines.Yield.Merchant._interact_with_trader_xy(  # pylint: disable=protected-access
                x,
                y,
                inventory_timeout_ms=2500,
                inventory_step_ms=10,
            )
        else:
            trader_items = list(trader_items)
        if not trader_items:
            ConsoleLog(MODULE_NAME, f"{phase_label} inventory did not load.", Console.MessageType.Warning)
            outcome.load_failures += 1
            self._debug_log(f"{phase_label}: trader inventory failed to load at {self._format_debug_coords(coords)}.")
            return outcome

        for planned_buy in rune_buys:
            safe_identifier = _normalize_rune_identifier(planned_buy.identifier)
            if not safe_identifier:
                continue

            trader_item_id = 0
            for candidate in trader_items:
                candidate_identifiers = self._get_standalone_rune_identifiers_for_item_id(int(candidate))
                if safe_identifier in candidate_identifiers:
                    trader_item_id = int(candidate)
                    break
            if trader_item_id <= 0:
                outcome.unavailable += max(0, int(planned_buy.quantity))
                ConsoleLog(
                    MODULE_NAME,
                    f"{planned_buy.label} was not offered by the Rune Trader.",
                    Console.MessageType.Warning,
                )
                continue

            completed_for_target = 0
            for _ in range(max(0, int(planned_buy.quantity))):
                quoted_value = yield from Routines.Yield.Merchant._wait_for_quote(  # pylint: disable=protected-access
                    GLOBAL_CACHE.Trading.Trader.RequestQuote,
                    trader_item_id,
                    timeout_ms=750,
                    step_ms=10,
                )
                if quoted_value <= 0:
                    outcome.quote_failures += 1
                    break
                gold_result = yield from self._ensure_gold_for_purchase(
                    quoted_value,
                    purpose=f"{phase_label} {planned_buy.label}",
                )
                if gold_result.opened_storage:
                    trader_items = yield from self._refresh_trader_items_after_gold_top_up(
                        coords,
                        using_existing_trader_items=using_existing_trader_items,
                        phase_label=phase_label,
                    )
                    if not trader_items:
                        outcome.load_failures += 1
                        break
                    trader_item_id = 0
                    for candidate in trader_items:
                        candidate_identifiers = self._get_standalone_rune_identifiers_for_item_id(int(candidate))
                        if safe_identifier in candidate_identifiers:
                            trader_item_id = int(candidate)
                            break
                    if trader_item_id <= 0:
                        outcome.unavailable += 1
                        break
                    quoted_value = yield from Routines.Yield.Merchant._wait_for_quote(  # pylint: disable=protected-access
                        GLOBAL_CACHE.Trading.Trader.RequestQuote,
                        trader_item_id,
                        timeout_ms=750,
                        step_ms=10,
                    )
                    if quoted_value <= 0:
                        outcome.quote_failures += 1
                        break
                    gold_result = yield from self._ensure_gold_for_purchase(
                        quoted_value,
                        purpose=f"{phase_label} {planned_buy.label}",
                    )
                    if not gold_result.ready:
                        outcome.gold_blocked += 1
                        break
                if not gold_result.ready:
                    outcome.gold_blocked += 1
                    self._debug_log(
                        f"{phase_label} blocked by gold: identifier={safe_identifier} quote={quoted_value} "
                        f"carried={gold_result.carried_gold} storage={gold_result.storage_gold} "
                        f"reason={gold_result.reason}"
                    )
                    break

                before_count = self._get_inventory_standalone_rune_identifier_count(safe_identifier)
                GLOBAL_CACHE.Trading.Trader.BuyItem(trader_item_id, quoted_value)
                completed = yield from Routines.Yield.Merchant._wait_for_transaction(  # pylint: disable=protected-access
                    timeout_ms=750,
                    step_ms=10,
                )
                if not completed:
                    outcome.timeout_failures += 1
                    break
                after_count = yield from self._wait_for_inventory_standalone_rune_identifier_count_at_least(
                    safe_identifier,
                    before_count + 1,
                    timeout_ms=1500,
                    step_ms=50,
                )
                if after_count <= before_count:
                    outcome.timeout_failures += 1
                    self._debug_log(
                        f"{phase_label} buy verification failed: identifier={safe_identifier} "
                        f"before={before_count} after={after_count}."
                    )
                    break
                outcome.completed += 1
                completed_for_target += 1
                yield from Routines.Yield.wait(40)

            if completed_for_target >= max(0, int(planned_buy.quantity)):
                self._apply_after_purchase_cleanup(planned_buy.cleanup, label=planned_buy.label)

        self._debug_log(
            f"{phase_label}: completed={outcome.completed}/{outcome.attempted} "
            f"unavailable={outcome.unavailable} quote_failures={outcome.quote_failures} "
            f"timeouts={outcome.timeout_failures} gold_blocked={outcome.gold_blocked} "
            f"load_failures={outcome.load_failures}"
        )
        return outcome

    def _buy_planned_scroll_trader_items(
        self,
        coords: tuple[float, float],
        scroll_buys: list[PlannedScrollTraderBuy],
        *,
        phase_label: str = "Scroll trader buys",
        trader_items: list[int] | None = None,
    ) -> ExecutionPhaseOutcome:
        outcome = ExecutionPhaseOutcome(
            label=phase_label,
            measure_label="items",
            attempted=sum(max(0, int(planned_buy.quantity)) for planned_buy in scroll_buys),
        )
        if not scroll_buys:
            return outcome

        self._debug_log(
            f"{phase_label}: coords={self._format_debug_coords(coords)} "
            f"planned_targets={len(scroll_buys)} planned_items={outcome.attempted}"
        )
        using_existing_trader_items = trader_items is not None
        if trader_items is None:
            x, y = coords
            trader_items = yield from Routines.Yield.Merchant._interact_with_trader_xy(  # pylint: disable=protected-access
                x,
                y,
                inventory_timeout_ms=2500,
                inventory_step_ms=10,
            )
        else:
            trader_items = list(trader_items)
        if not trader_items:
            ConsoleLog(MODULE_NAME, f"{phase_label} inventory did not load.", Console.MessageType.Warning)
            outcome.load_failures += 1
            self._debug_log(f"{phase_label}: trader inventory failed to load at {self._format_debug_coords(coords)}.")
            return outcome

        for planned_buy in scroll_buys:
            safe_model_id = max(0, _safe_int(planned_buy.model_id, 0))
            if safe_model_id <= 0 or not _is_scroll_trader_stock_model(safe_model_id):
                outcome.unavailable += max(0, int(planned_buy.quantity))
                continue

            trader_item_id = 0
            for candidate in trader_items:
                if int(GLOBAL_CACHE.Item.GetModelID(candidate)) == safe_model_id:
                    trader_item_id = int(candidate)
                    break
            if trader_item_id <= 0:
                outcome.unavailable += max(0, int(planned_buy.quantity))
                ConsoleLog(
                    MODULE_NAME,
                    f"{planned_buy.label} was not offered by the {self._get_scroll_trader_service_label()}.",
                    Console.MessageType.Warning,
                )
                continue

            completed_for_target = 0
            for _ in range(max(0, int(planned_buy.quantity))):
                quoted_value = yield from Routines.Yield.Merchant._wait_for_quote(  # pylint: disable=protected-access
                    GLOBAL_CACHE.Trading.Trader.RequestQuote,
                    trader_item_id,
                    timeout_ms=750,
                    step_ms=10,
                )
                if quoted_value <= 0:
                    outcome.quote_failures += 1
                    break
                gold_result = yield from self._ensure_gold_for_purchase(
                    quoted_value,
                    purpose=f"{phase_label} {planned_buy.model_id}",
                )
                if gold_result.opened_storage:
                    trader_items = yield from self._refresh_trader_items_after_gold_top_up(
                        coords,
                        using_existing_trader_items=using_existing_trader_items,
                        phase_label=phase_label,
                    )
                    if not trader_items:
                        outcome.load_failures += 1
                        break
                    trader_item_id = self._find_offered_model_item_id(trader_items, safe_model_id)
                    if trader_item_id <= 0:
                        outcome.unavailable += 1
                        break
                    quoted_value = yield from Routines.Yield.Merchant._wait_for_quote(  # pylint: disable=protected-access
                        GLOBAL_CACHE.Trading.Trader.RequestQuote,
                        trader_item_id,
                        timeout_ms=750,
                        step_ms=10,
                    )
                    if quoted_value <= 0:
                        outcome.quote_failures += 1
                        break
                    gold_result = yield from self._ensure_gold_for_purchase(
                        quoted_value,
                        purpose=f"{phase_label} {planned_buy.model_id}",
                    )
                    if not gold_result.ready:
                        outcome.gold_blocked += 1
                        break
                if not gold_result.ready:
                    outcome.gold_blocked += 1
                    self._debug_log(
                        f"{phase_label} blocked by gold: model={safe_model_id} quote={quoted_value} "
                        f"carried={gold_result.carried_gold} storage={gold_result.storage_gold} "
                        f"reason={gold_result.reason}"
                    )
                    break

                try:
                    before_count = max(0, int(GLOBAL_CACHE.Inventory.GetModelCount(safe_model_id)))
                except Exception as exc:
                    outcome.load_failures += 1
                    self._debug_log(f"{phase_label} could not read inventory count for model={safe_model_id}: {exc}")
                    break
                GLOBAL_CACHE.Trading.Trader.BuyItem(trader_item_id, quoted_value)
                completed = yield from Routines.Yield.Merchant._wait_for_transaction(  # pylint: disable=protected-access
                    timeout_ms=750,
                    step_ms=10,
                )
                if not completed:
                    outcome.timeout_failures += 1
                    break
                after_count = yield from self._wait_for_inventory_model_count_at_least(
                    safe_model_id,
                    before_count + 1,
                    timeout_ms=1500,
                    step_ms=50,
                )
                if after_count <= before_count:
                    outcome.timeout_failures += 1
                    self._debug_log(
                        f"{phase_label} buy verification failed: model={safe_model_id} "
                        f"before={before_count} after={after_count}."
                    )
                    break
                outcome.completed += 1
                completed_for_target += 1
                yield from Routines.Yield.wait(40)

            if completed_for_target >= max(0, int(planned_buy.quantity)):
                self._apply_after_purchase_cleanup(planned_buy.cleanup, label=planned_buy.label)

        self._debug_log(
            f"{phase_label}: completed={outcome.completed}/{outcome.attempted} "
            f"unavailable={outcome.unavailable} quote_failures={outcome.quote_failures} "
            f"timeouts={outcome.timeout_failures} gold_blocked={outcome.gold_blocked} "
            f"load_failures={outcome.load_failures}"
        )
        return outcome

    def _format_execution_phase_summary(self, outcome: ExecutionPhaseOutcome) -> str:
        if (
            outcome.attempted <= 0
            and outcome.completed <= 0
            and outcome.unavailable <= 0
            and outcome.quote_failures <= 0
            and outcome.timeout_failures <= 0
            and outcome.load_failures <= 0
            and outcome.gold_blocked <= 0
            and outcome.depleted <= 0
        ):
            return ""

        parts: list[str] = []
        if outcome.attempted > 0:
            parts.append(f"{outcome.completed}/{outcome.attempted} {outcome.measure_label}")
        elif outcome.completed > 0:
            parts.append(f"{outcome.completed} {outcome.measure_label}")
        if outcome.unavailable > 0:
            parts.append(f"{outcome.unavailable} unavailable")
        if outcome.quote_failures > 0:
            parts.append(f"{outcome.quote_failures} quote failure(s)")
        if outcome.timeout_failures > 0:
            parts.append(f"{outcome.timeout_failures} timeout(s)")
        if outcome.load_failures > 0:
            parts.append(f"{outcome.load_failures} inventory load failure(s)")
        if outcome.gold_blocked > 0:
            parts.append(f"{outcome.gold_blocked} blocked by gold")
        if outcome.depleted > 0:
            parts.append(f"{outcome.depleted} depleted")
        return f"{outcome.label}: {', '.join(parts)}."

    def _open_xunlai_and_scan_preview(self):
        self.storage_scan_running = True
        self.last_error = ""
        try:
            if bool(GLOBAL_CACHE.Inventory.IsStorageOpen()):
                self._scan_preview()
                self.status_message = "Exact storage scan complete. Preview refreshed with Xunlai counts."
                return

            self.status_message = "Opening Xunlai for exact storage scan..."
            opened = yield from self._ensure_storage_open(purpose="exact storage preview scan")
            if not opened:
                self.status_message = "Could not open Xunlai for exact storage scan."
                return

            yield from Routines.Yield.wait(150)
            self._scan_preview()
            self.status_message = "Exact storage scan complete. Preview refreshed with Xunlai counts."
        except Exception as exc:
            self.last_error = f"{exc}"
            self.status_message = "Exact storage scan failed. See the console log for details."
            ConsoleLog(MODULE_NAME, f"Exact storage scan error: {exc}", Console.MessageType.Error)
            ConsoleLog(MODULE_NAME, traceback.format_exc(), Console.MessageType.Error)
        finally:
            self.storage_scan_running = False
            yield

    def _scan_preview(self):
        self._invalidate_supported_context_cache()
        if self._should_use_consumable_crafter_multi_stop_route():
            projected_target_outpost_id, projected_target_outpost_name = self._get_consumable_crafter_multi_stop_target()
        else:
            projected_target_outpost_id, projected_target_outpost_name = self._get_preview_projection_target()
        self.preview_plan = self._build_plan(projected_preview=True)
        self.preview_ready = True
        self._set_preview_projection_state(
            requires_travel=projected_target_outpost_id > 0,
            target_outpost_id=projected_target_outpost_id,
            target_outpost_name=projected_target_outpost_name,
        )
        self._clear_preview_inventory_diff()
        if self.preview_plan.multi_stop_route:
            embark_label = self.preview_plan.multi_stop_consumable_outpost_name or self._get_embark_beach_outpost_name()
            destination_label = self.preview_plan.multi_stop_destination_outpost_name
            if destination_label:
                self.status_message = (
                    f"Multi-stop preview complete. Travel + Execute will craft Consumable Crafter targets at {embark_label}, "
                    f"then travel to {destination_label} for remaining Merchant Rules work."
                )
            else:
                self.status_message = (
                    f"Multi-stop preview complete. Travel + Execute will craft Consumable Crafter targets at {embark_label} and stop there."
                )
        elif self._preview_has_execute_travel_pending():
            if self.preview_plan.has_actions:
                self.status_message = (
                    f"Projected preview complete. Travel + Execute will travel to {projected_target_outpost_name}, "
                    "rebuild live, and then run the merchant plan. Execute Here can still run any green local entries."
                )
            else:
                self.status_message = (
                    f"Projected preview complete. Travel + Execute will still travel to {projected_target_outpost_name}, "
                    "but no merchant work is currently projected."
                )
        elif self.preview_plan.has_actions:
            self.status_message = "Preview complete. Review the plan, then run Travel + Execute or Execute Here when ready."
        else:
            self.status_message = "Preview complete. No actionable merchant work was found."
        self.last_error = ""

    def _travel_and_preview_only(self):
        self.travel_preview_running = True
        self.last_error = ""
        self.last_execution_summary = ""
        try:
            target_outpost_id = max(0, int(self.target_outpost_id)) if self.auto_travel_enabled else 0
            target_outpost_name = self._get_outpost_name(target_outpost_id) if target_outpost_id > 0 else ""
            self._debug_log(
                f"Travel + Preview start: auto_travel={self.auto_travel_enabled} "
                f"target={target_outpost_name} ({target_outpost_id})"
            )
            if target_outpost_id > 0 and not self._is_travel_target_reached(target_outpost_id):
                self.status_message = f"Traveling to {target_outpost_name} for preview."
                travel_ok = yield from self._travel_to_target_outpost(target_outpost_id)
                if not travel_ok:
                    self.status_message = f"Failed to travel to {target_outpost_name} for preview."
                    self._debug_log(f"Travel + Preview failed to reach {target_outpost_name} ({target_outpost_id}).")
                    return
                self._debug_log(f"Travel + Preview reached {target_outpost_name} ({target_outpost_id}).")
                yield from Routines.Yield.wait(300)

            self._invalidate_supported_context_cache()
            self.preview_plan = self._build_plan()
            self.preview_ready = True
            self._clear_preview_projection_state()
            self._clear_preview_inventory_diff()
            if self.preview_plan.travel_to_outpost_id > 0:
                self.status_message = "Travel preview completed, but the target outpost still needs to be reached."
            elif self.preview_plan.has_actions:
                self.status_message = "Travel and preview complete. Review the refreshed merchant plan."
            else:
                self.status_message = "Travel and preview complete. No actionable merchant work was found."
        except Exception as exc:
            self.last_error = f"{exc}"
            self.status_message = "Travel + Preview failed. See the console log for details."
            ConsoleLog(MODULE_NAME, f"Travel + Preview error: {exc}", Console.MessageType.Error)
            ConsoleLog(MODULE_NAME, traceback.format_exc(), Console.MessageType.Error)
        finally:
            self.travel_preview_running = False
            yield

    def _merge_phase_outcome(self, total: ExecutionPhaseOutcome, part: ExecutionPhaseOutcome) -> None:
        total.attempted += max(0, int(part.attempted))
        total.completed += max(0, int(part.completed))
        total.unavailable += max(0, int(part.unavailable))
        total.quote_failures += max(0, int(part.quote_failures))
        total.timeout_failures += max(0, int(part.timeout_failures))
        total.load_failures += max(0, int(part.load_failures))
        total.gold_blocked += max(0, int(part.gold_blocked))
        total.depleted += max(0, int(part.depleted))

    def _merge_merchant_buy_result(
        self,
        total: ExecutionPhaseOutcome,
        result: object,
        requested_quantity: int,
    ) -> None:
        safe_requested_quantity = max(0, int(requested_quantity))
        if isinstance(result, ExecutionPhaseOutcome):
            total.completed += max(0, int(result.completed))
            total.unavailable += max(0, int(result.unavailable))
            total.quote_failures += max(0, int(result.quote_failures))
            total.timeout_failures += max(0, int(result.timeout_failures))
            total.load_failures += max(0, int(result.load_failures))
            total.gold_blocked += max(0, int(result.gold_blocked))
            total.depleted += max(0, int(result.depleted))
            return
        if isinstance(result, bool):
            if result:
                total.completed += safe_requested_quantity
            else:
                total.unavailable += safe_requested_quantity
            return
        try:
            completed_quantity = max(0, min(safe_requested_quantity, int(result or 0)))
        except Exception:
            completed_quantity = 0
        total.completed += completed_quantity
        total.unavailable += max(0, safe_requested_quantity - completed_quantity)

    def _sum_item_quantities(self, items: list[InventoryItemInfo]) -> int:
        return sum(max(1, int(item.quantity)) for item in items if int(item.item_id) > 0)

    def _get_xunlai_storage_keep_available(
        self,
        rule: SellRule,
        model_id: int,
        regular_storage_items: list[InventoryItemInfo],
        material_storage_items: list[InventoryItemInfo],
    ) -> int:
        if not bool(getattr(rule, "sell_from_xunlai", False)):
            return 0
        safe_model_id = max(0, int(model_id))
        if safe_model_id <= 0:
            return 0
        source_items = list(regular_storage_items)
        if bool(getattr(rule, "include_material_storage", False)) and _sell_rule_can_include_material_storage(rule):
            source_items = [*material_storage_items, *source_items]
        return self._sum_item_quantities(
            [item for item in source_items if int(item.model_id) == safe_model_id]
        )

    def _build_xunlai_storage_keep_reservations(
        self,
        source_items: list[tuple[InventoryItemInfo, str]],
        keep_count: int,
    ) -> tuple[dict[int, int], int]:
        remaining_keep = max(0, int(keep_count))
        if remaining_keep <= 0:
            return {}, 0

        reservations: dict[int, int] = {}
        reserved_total = 0
        reserve_order = sorted(
            source_items,
            key=lambda pair: (
                0 if str(pair[1]) == "Material Storage" else 1,
                int(pair[0].item_id),
            ),
        )
        for item, _source_label in reserve_order:
            if remaining_keep <= 0:
                break
            item_quantity = max(1, int(item.quantity))
            reserve_quantity = min(item_quantity, remaining_keep)
            if reserve_quantity <= 0:
                continue
            reservations[int(item.item_id)] = reserve_quantity
            reserved_total += reserve_quantity
            remaining_keep -= reserve_quantity
        return reservations, reserved_total

    def _clone_xunlai_sell_rule_for_pass(
        self,
        rule: SellRule,
        *,
        model_keep_overrides: dict[tuple[str, int], int],
        rune_keep_overrides: dict[tuple[str, str], int],
        include_equippable: bool,
    ) -> SellRule | None:
        safe_rule_id = _normalize_rule_id(getattr(rule, "rule_id", ""))
        cloned_rule = replace(rule)
        cloned_rule.sell_from_xunlai = False
        cloned_rule.include_material_storage = False

        if rule.kind in (SELL_KIND_COMMON_MATERIALS, SELL_KIND_EXPLICIT_MODELS):
            next_targets: list[WhitelistTarget] = []
            for target in _normalize_whitelist_targets(getattr(rule, "whitelist_targets", [])):
                key = (safe_rule_id, int(target.model_id))
                if key not in model_keep_overrides:
                    continue
                next_targets.append(
                    WhitelistTarget(
                        model_id=int(target.model_id),
                        keep_count=max(0, int(model_keep_overrides[key])),
                        deposit_to_storage=False,
                    )
                )
            if not next_targets:
                return None
            cloned_rule.whitelist_targets = next_targets
            cloned_rule.model_ids = _get_whitelist_target_model_ids(next_targets)
            cloned_rule.keep_count = 0
            return cloned_rule

        if rule.kind == SELL_KIND_RUNE_TRADER_TARGET:
            next_targets: list[RuneSellTarget] = []
            for target in _normalize_rune_sell_targets(getattr(rule, "rune_sell_targets", [])):
                key = (safe_rule_id, _normalize_rune_identifier(target.identifier))
                if key not in rune_keep_overrides:
                    continue
                next_targets.append(
                    RuneSellTarget(
                        identifier=key[1],
                        keep_count=max(0, int(rune_keep_overrides[key])),
                    )
                )
            if not next_targets:
                return None
            cloned_rule.rune_sell_targets = next_targets
            return cloned_rule

        if rule.kind in (SELL_KIND_WEAPONS, SELL_KIND_ARMOR) and include_equippable:
            return cloned_rule

        return None

    def _build_xunlai_sell_subplan(self, rules: list[SellRule]) -> PlanResult:
        original_buy_rules = self.buy_rules
        original_sell_rules = self.sell_rules
        original_destroy_rules = self.destroy_rules
        original_identify_settings = self.identify_settings
        original_cleanup_targets = self.cleanup_targets
        original_cleanup_blacklist_model_ids = self.cleanup_blacklist_model_ids
        original_cleanup_protection_sources = self.cleanup_protection_sources
        try:
            self.buy_rules = []
            self.sell_rules = rules
            self.destroy_rules = []
            self.identify_settings = IdentifySettings()
            self.cleanup_targets = []
            self.cleanup_blacklist_model_ids = []
            self.cleanup_protection_sources = []
            return self._build_plan(
                ignore_travel_target=True,
                allow_consumable_multi_stop=False,
                exclude_consumable_crafter=True,
            )
        finally:
            self.buy_rules = original_buy_rules
            self.sell_rules = original_sell_rules
            self.destroy_rules = original_destroy_rules
            self.identify_settings = original_identify_settings
            self.cleanup_targets = original_cleanup_targets
            self.cleanup_blacklist_model_ids = original_cleanup_blacklist_model_ids
            self.cleanup_protection_sources = original_cleanup_protection_sources

    def _get_xunlai_model_target_withdraw_quantity(
        self,
        *,
        current_quantity: int,
        storage_quantity: int,
        keep_count: int,
        model_id: int,
        destination: str,
    ) -> int:
        safe_storage_quantity = max(0, int(storage_quantity))
        if safe_storage_quantity <= 0:
            return 0

        safe_keep_count = max(0, int(keep_count))
        safe_current_quantity = max(0, int(current_quantity))
        if (
            safe_keep_count > 0
            and destination == MERCHANT_TYPE_MATERIALS
            and max(0, int(model_id)) in COMMON_CRAFTING_MATERIAL_MODEL_IDS
        ):
            batch_size = max(1, int(self._get_material_batch_size(model_id)))
            combined_quantity = safe_current_quantity + safe_storage_quantity
            if ((combined_quantity - safe_keep_count) // batch_size) <= 0:
                return 0
            return safe_storage_quantity

        sellable_quantity = max(0, safe_current_quantity + safe_storage_quantity - safe_keep_count)
        withdraw_quantity = min(safe_storage_quantity, sellable_quantity)
        if withdraw_quantity <= 0:
            return 0
        return max(0, int(withdraw_quantity))

    def _get_xunlai_sell_withdraw_label(self, item: InventoryItemInfo) -> str:
        if int(item.model_id) in ALL_CRAFTING_MATERIAL_MODEL_IDS:
            return self._format_model_label_short(int(item.model_id))
        return str(item.name or f"Item {int(item.item_id)}")

    def _append_xunlai_protected_sell_withdraw_preview_entries(
        self,
        entries: list[ExecutionPlanEntry] | None,
        source_items: list[tuple[InventoryItemInfo, str, str]],
        *,
        rule_reference: str,
    ) -> None:
        if entries is None:
            return
        for item, _source_label, protection_reason in source_items:
            entries.append(
                ExecutionPlanEntry(
                    "withdraw",
                    MERCHANT_TYPE_STORAGE,
                    self._get_xunlai_sell_withdraw_label(item),
                    max(1, int(item.quantity)),
                    PLAN_STATE_SKIPPED,
                    f"Blocked by {rule_reference}: {protection_reason}",
                    model_id=int(item.model_id),
                )
            )

    def _append_xunlai_sell_withdrawals(
        self,
        transfers: list[PlannedStorageTransfer],
        source_items: list[tuple[InventoryItemInfo, str]],
        *,
        quantity: int,
        rule_reference: str,
        key: str,
        reserved_quantities: dict[int, int] | None = None,
    ) -> None:
        remaining = max(0, int(quantity))
        if remaining <= 0:
            return

        reserved_quantities = reserved_quantities or {}
        for item, source_label in source_items:
            if remaining <= 0:
                break
            source_quantity = max(1, int(item.quantity))
            reserved_quantity = max(0, int(reserved_quantities.get(int(item.item_id), 0)))
            available_quantity = max(0, source_quantity - reserved_quantity)
            move_quantity = min(remaining, available_quantity)
            if move_quantity <= 0:
                continue
            transfers.append(
                PlannedStorageTransfer(
                    direction=STORAGE_TRANSFER_WITHDRAW,
                    key=key,
                    label=self._get_xunlai_sell_withdraw_label(item),
                    item_id=int(item.item_id),
                    quantity=move_quantity,
                    model_id=int(item.model_id),
                    reason=f"{rule_reference}: Sell from Xunlai too ({source_label}).",
                )
            )
            remaining -= move_quantity

    def _xunlai_model_target_has_sell_service(
        self,
        rule: SellRule,
        model_id: int,
        source_items: list[tuple[InventoryItemInfo, str]],
        coords: dict[str, tuple[float, float] | None],
        *,
        withdraw_quantity: int,
        keep_count: int,
    ) -> bool:
        if rule.kind == SELL_KIND_COMMON_MATERIALS:
            destination = self._get_material_merchant_type_by_model(model_id)
            if coords.get(destination) is not None:
                return True
            return bool(
                destination == MERCHANT_TYPE_MATERIALS
                and max(0, int(keep_count)) <= 0
                and max(0, int(withdraw_quantity)) < max(1, int(self._get_material_batch_size(model_id)))
                and coords.get(MERCHANT_TYPE_MERCHANT) is not None
            )

        for item, _source_label in source_items:
            destination = self._get_explicit_sell_destination(item)
            if coords.get(destination) is not None:
                return True
            if (
                destination == MERCHANT_TYPE_MATERIALS
                and max(0, int(keep_count)) <= 0
                and max(0, int(withdraw_quantity)) < max(1, int(self._get_material_batch_size(item.model_id)))
                and coords.get(MERCHANT_TYPE_MERCHANT) is not None
            ):
                return True
        return False

    def _plan_xunlai_sell_withdrawals(
        self,
        enabled_xunlai_rules: list[tuple[int, SellRule]],
        current_items: list[InventoryItemInfo],
        regular_storage_items: list[InventoryItemInfo],
        material_storage_items: list[InventoryItemInfo],
        coords: dict[str, tuple[float, float] | None],
        *,
        protected_preview_entries: list[ExecutionPlanEntry] | None = None,
    ) -> tuple[list[PlannedStorageTransfer], list[SellRule]]:
        all_enabled_sell_rules = self._collect_enabled_sell_rules()
        transfers: list[PlannedStorageTransfer] = []
        model_keep_overrides: dict[tuple[str, int], int] = {}
        rune_keep_overrides: dict[tuple[str, str], int] = {}
        equippable_rule_ids: set[str] = set()
        claimed_storage_item_ids: set[int] = set()

        for rule_index, rule in enabled_xunlai_rules:
            safe_rule_id = _normalize_rule_id(getattr(rule, "rule_id", ""))
            if not safe_rule_id:
                continue
            rule_reference = self._format_sell_rule_reference(rule_index, rule)

            regular_sources = [
                (item, "regular Xunlai item panes")
                for item in regular_storage_items
                if int(item.item_id) not in claimed_storage_item_ids
            ]
            material_sources = [
                (item, "Material Storage")
                for item in material_storage_items
                if bool(getattr(rule, "include_material_storage", False))
                and _sell_rule_can_include_material_storage(rule)
                and int(item.item_id) not in claimed_storage_item_ids
                and int(item.model_id) in ALL_CRAFTING_MATERIAL_MODEL_IDS
            ]

            if rule.kind in (SELL_KIND_COMMON_MATERIALS, SELL_KIND_EXPLICIT_MODELS):
                for target in _normalize_whitelist_targets(getattr(rule, "whitelist_targets", [])):
                    target_model_id = max(0, int(target.model_id))
                    if target_model_id <= 0:
                        continue
                    if rule.kind == SELL_KIND_COMMON_MATERIALS and target_model_id not in ALL_CRAFTING_MATERIAL_MODEL_IDS:
                        continue

                    candidate_sources = [
                        (item, source_label)
                        for item, source_label in [*regular_sources, *material_sources]
                        if int(item.model_id) == target_model_id
                    ]
                    matching_sources: list[tuple[InventoryItemInfo, str]] = []
                    protected_sources: list[tuple[InventoryItemInfo, str, str]] = []
                    for item, source_label in candidate_sources:
                        hard_protection = self._get_hard_protection_hit(item, all_enabled_sell_rules)
                        if hard_protection is not None:
                            _destination, protection_reason = hard_protection
                            protected_sources.append((item, source_label, protection_reason))
                            claimed_storage_item_ids.add(int(item.item_id))
                            continue
                        matching_sources.append((item, source_label))
                    self._append_xunlai_protected_sell_withdraw_preview_entries(
                        protected_preview_entries,
                        protected_sources,
                        rule_reference=rule_reference,
                    )
                    if not matching_sources:
                        continue

                    current_matching_items = [
                        item
                        for item in current_items
                        if int(item.model_id) == target_model_id
                    ]
                    current_quantity = self._sum_item_quantities(current_matching_items)
                    storage_quantity = self._sum_item_quantities([item for item, _source_label in matching_sources])
                    destination = (
                        self._get_material_merchant_type_by_model(target_model_id)
                        if rule.kind == SELL_KIND_COMMON_MATERIALS
                        else self._get_explicit_sell_destination(matching_sources[0][0])
                    )
                    storage_keep_reservations, storage_reserved_keep = self._build_xunlai_storage_keep_reservations(
                        matching_sources,
                        max(0, int(target.keep_count)),
                    )
                    inventory_keep_count = max(0, int(target.keep_count) - storage_reserved_keep)
                    withdraw_quantity = max(0, storage_quantity - storage_reserved_keep)
                    for item, _source_label in matching_sources:
                        claimed_storage_item_ids.add(int(item.item_id))
                    if withdraw_quantity <= 0:
                        continue
                    if current_quantity + withdraw_quantity <= inventory_keep_count:
                        continue
                    if not self._xunlai_model_target_has_sell_service(
                        rule,
                        target_model_id,
                        matching_sources,
                        coords,
                        withdraw_quantity=withdraw_quantity,
                        keep_count=inventory_keep_count,
                    ):
                        continue

                    model_keep_overrides[(safe_rule_id, target_model_id)] = inventory_keep_count
                    self._append_xunlai_sell_withdrawals(
                        transfers,
                        matching_sources,
                        quantity=withdraw_quantity,
                        rule_reference=rule_reference,
                        key=f"xunlai_sell:{safe_rule_id}:model:{target_model_id}",
                        reserved_quantities=storage_keep_reservations,
                    )
                continue

            if rule.kind == SELL_KIND_RUNE_TRADER_TARGET:
                if coords.get(MERCHANT_TYPE_RUNE_TRADER) is None:
                    continue
                for target in _normalize_rune_sell_targets(getattr(rule, "rune_sell_targets", [])):
                    target_identifier = _normalize_rune_identifier(target.identifier)
                    if not target_identifier:
                        continue
                    candidate_sources = [
                        (item, source_label)
                        for item, source_label in regular_sources
                        if item.standalone_kind == RUNE_STANDALONE_KIND
                        and target_identifier in item.rune_identifiers
                    ]
                    matching_sources: list[tuple[InventoryItemInfo, str]] = []
                    protected_sources: list[tuple[InventoryItemInfo, str, str]] = []
                    for item, source_label in candidate_sources:
                        hard_protection = self._get_hard_protection_hit(item, all_enabled_sell_rules)
                        if hard_protection is not None:
                            _destination, protection_reason = hard_protection
                            protected_sources.append((item, source_label, protection_reason))
                            claimed_storage_item_ids.add(int(item.item_id))
                            continue
                        matching_sources.append((item, source_label))
                    self._append_xunlai_protected_sell_withdraw_preview_entries(
                        protected_preview_entries,
                        protected_sources,
                        rule_reference=rule_reference,
                    )
                    if not matching_sources:
                        continue

                    current_matching_items = [
                        item
                        for item in current_items
                        if item.standalone_kind == RUNE_STANDALONE_KIND
                        and target_identifier in item.rune_identifiers
                    ]
                    current_quantity = self._sum_item_quantities(current_matching_items)
                    storage_quantity = self._sum_item_quantities([item for item, _source_label in matching_sources])
                    withdraw_quantity = max(
                        0,
                        min(
                            storage_quantity,
                            current_quantity + storage_quantity - max(0, int(target.keep_count)),
                        ),
                    )
                    for item, _source_label in matching_sources:
                        claimed_storage_item_ids.add(int(item.item_id))
                    if withdraw_quantity <= 0:
                        continue
                    rune_keep_overrides[(safe_rule_id, target_identifier)] = current_quantity
                    self._append_xunlai_sell_withdrawals(
                        transfers,
                        matching_sources,
                        quantity=withdraw_quantity,
                        rule_reference=rule_reference,
                        key=f"xunlai_sell:{safe_rule_id}:rune:{target_identifier}",
                    )
                continue

            if rule.kind in (SELL_KIND_WEAPONS, SELL_KIND_ARMOR):
                matching_sources: list[tuple[InventoryItemInfo, str]] = []
                for item, source_label in regular_sources:
                    destination = self._get_equippable_rule_destination(item, rule)
                    if not destination:
                        continue
                    if coords.get(destination) is None:
                        claimed_storage_item_ids.add(int(item.item_id))
                        continue
                    if not self._rule_matches_selected_rarity(item, rule):
                        continue
                    hard_protection = self._get_hard_protection_hit(item, all_enabled_sell_rules)
                    if hard_protection is not None:
                        _destination, protection_reason = hard_protection
                        self._append_xunlai_protected_sell_withdraw_preview_entries(
                            protected_preview_entries,
                            [(item, source_label, protection_reason)],
                            rule_reference=rule_reference,
                        )
                        claimed_storage_item_ids.add(int(item.item_id))
                        continue
                    matching_sources.append((item, source_label))
                    claimed_storage_item_ids.add(int(item.item_id))
                if not matching_sources:
                    continue
                equippable_rule_ids.add(safe_rule_id)
                self._append_xunlai_sell_withdrawals(
                    transfers,
                    matching_sources,
                    quantity=self._sum_item_quantities([item for item, _source_label in matching_sources]),
                    rule_reference=rule_reference,
                    key=f"xunlai_sell:{safe_rule_id}:equippable",
                )

        adjusted_rules: list[SellRule] = []
        for _rule_index, rule in enabled_xunlai_rules:
            cloned_rule = self._clone_xunlai_sell_rule_for_pass(
                rule,
                model_keep_overrides=model_keep_overrides,
                rune_keep_overrides=rune_keep_overrides,
                include_equippable=_normalize_rule_id(getattr(rule, "rule_id", "")) in equippable_rule_ids,
            )
            if cloned_rule is not None:
                adjusted_rules.append(cloned_rule)

        return transfers, adjusted_rules

    def _execute_sell_actions_for_plan(
        self,
        plan: PlanResult,
        *,
        phase_label: str,
    ) -> ExecutionPhaseOutcome:
        outcome = ExecutionPhaseOutcome(label=phase_label, measure_label="sell action(s)")

        material_coords = plan.coords.get(MERCHANT_TYPE_MATERIALS)
        common_material_sales = [sale for sale in plan.material_sales if sale.merchant_type == MERCHANT_TYPE_MATERIALS]
        if material_coords and common_material_sales:
            material_outcome = yield from self._sell_planned_materials(
                material_coords,
                common_material_sales,
                phase_label=f"{phase_label} material sales",
            )
            self._merge_phase_outcome(outcome, material_outcome)

        rare_material_coords = plan.coords.get(MERCHANT_TYPE_RARE_MATERIALS)
        rare_material_sales = [sale for sale in plan.material_sales if sale.merchant_type == MERCHANT_TYPE_RARE_MATERIALS]
        if rare_material_coords and rare_material_sales:
            rare_outcome = yield from self._sell_planned_materials(
                rare_material_coords,
                rare_material_sales,
                phase_label=f"{phase_label} rare material sales",
            )
            self._merge_phase_outcome(outcome, rare_outcome)

        merchant_outcome = yield from self._execute_merchant_sell_phase(
            plan.coords.get(MERCHANT_TYPE_MERCHANT),
            plan.merchant_sell_item_ids,
        )
        merchant_outcome.label = f"{phase_label} merchant sales"
        self._merge_phase_outcome(outcome, merchant_outcome)

        rune_trader_coords = plan.coords.get(MERCHANT_TYPE_RUNE_TRADER)
        if rune_trader_coords and plan.rune_trader_sales:
            rune_outcome = yield from self._sell_planned_trader_items(
                rune_trader_coords,
                plan.rune_trader_sales,
                phase_label=f"{phase_label} rune trader sales",
            )
            self._merge_phase_outcome(outcome, rune_outcome)

        return outcome

    def _execute_xunlai_sell_withdraw_phase(
        self,
        plan: PlanResult,
        *,
        local_only: bool = False,
        storage_available_here: bool = False,
    ) -> ExecutionPhaseOutcome:
        enabled_xunlai_rules = self._collect_enabled_xunlai_sell_rules()
        outcome = ExecutionPhaseOutcome(label="Xunlai sell pre-pull", measure_label="items")
        if not enabled_xunlai_rules:
            return outcome

        if local_only and not storage_available_here:
            outcome.load_failures += 1
            return outcome

        storage_ready = self._is_storage_open()
        if not storage_ready:
            storage_ready = yield from self._ensure_storage_open(purpose="Sell from Xunlai too")
        if not storage_ready:
            outcome.load_failures += 1
            ConsoleLog(MODULE_NAME, "Could not open Xunlai for Sell from Xunlai too.", Console.MessageType.Warning)
            return outcome

        current_items = self._collect_inventory_items()
        regular_storage_items = self._collect_storage_items()
        include_material_storage = any(
            bool(getattr(rule, "include_material_storage", False))
            and _sell_rule_can_include_material_storage(rule)
            for _rule_index, rule in enabled_xunlai_rules
        )
        material_storage_items = self._collect_material_storage_items() if include_material_storage else []
        transfers, _adjusted_rules = self._plan_xunlai_sell_withdrawals(
            enabled_xunlai_rules,
            current_items,
            regular_storage_items,
            material_storage_items,
            plan.coords,
        )
        self._debug_log(
            f"Xunlai sell pre-pull: enabled_rules={len(enabled_xunlai_rules)} "
            f"inventory_items={len(current_items)} regular_storage_items={len(regular_storage_items)} "
            f"material_storage_items={len(material_storage_items)} include_material_storage={include_material_storage} "
            f"transfers={len(transfers)} quantity={sum(max(0, int(transfer.quantity)) for transfer in transfers)}"
        )
        if not transfers:
            return outcome

        transfer_outcome = yield from self._execute_storage_transfers(
            transfers,
            phase_label="Xunlai sell pre-pull",
        )
        self._merge_phase_outcome(outcome, transfer_outcome)
        return outcome

    def _execute_xunlai_sell_phase(
        self,
        plan: PlanResult,
        *,
        local_only: bool = False,
        storage_available_here: bool = False,
    ) -> ExecutionPhaseOutcome:
        enabled_xunlai_rules = self._collect_enabled_xunlai_sell_rules()
        outcome = ExecutionPhaseOutcome(label="Xunlai sells", measure_label="sell action(s)")
        if not enabled_xunlai_rules:
            self._debug_log("Xunlai sell phase skipped: no enabled Sell from Xunlai too rules.")
            return outcome

        if local_only and not storage_available_here:
            outcome.load_failures += 1
            return outcome

        storage_ready = self._is_storage_open()
        if not storage_ready:
            storage_ready = yield from self._ensure_storage_open(purpose="Sell from Xunlai too")
        if not storage_ready:
            outcome.load_failures += 1
            ConsoleLog(MODULE_NAME, "Could not open Xunlai for Sell from Xunlai too.", Console.MessageType.Warning)
            return outcome

        max_passes = 40
        for pass_index in range(max_passes):
            current_items = self._collect_inventory_items()
            regular_storage_items = self._collect_storage_items()
            include_material_storage = any(
                bool(getattr(rule, "include_material_storage", False))
                and _sell_rule_can_include_material_storage(rule)
                for _rule_index, rule in enabled_xunlai_rules
            )
            material_storage_items = self._collect_material_storage_items() if include_material_storage else []
            self._debug_log(
                f"Xunlai sell pass {pass_index + 1}: enabled_rules={len(enabled_xunlai_rules)} "
                f"inventory_items={len(current_items)} regular_storage_items={len(regular_storage_items)} "
                f"material_storage_items={len(material_storage_items)} include_material_storage={include_material_storage}"
            )
            transfers, adjusted_rules = self._plan_xunlai_sell_withdrawals(
                enabled_xunlai_rules,
                current_items,
                regular_storage_items,
                material_storage_items,
                plan.coords,
            )
            if not transfers or not adjusted_rules:
                self._debug_log(
                    f"Xunlai sell pass {pass_index + 1}: no withdrawable matching storage stacks "
                    f"(transfers={len(transfers)} adjusted_rules={len(adjusted_rules)})."
                )
                break

            self._debug_log(
                f"Xunlai sell pass {pass_index + 1}: transfers={len(transfers)} "
                f"quantity={sum(max(0, int(transfer.quantity)) for transfer in transfers)} "
                f"rules={len(adjusted_rules)}"
            )
            transfer_outcome = yield from self._execute_storage_transfers(
                transfers,
                phase_label="Xunlai sell withdraws",
            )
            outcome.timeout_failures += max(0, int(transfer_outcome.timeout_failures))
            outcome.load_failures += max(0, int(transfer_outcome.load_failures))
            outcome.depleted += max(0, int(transfer_outcome.depleted))
            if transfer_outcome.completed <= 0:
                break

            yield from Routines.Yield.wait(150)
            sell_plan = self._build_xunlai_sell_subplan(adjusted_rules)
            sell_outcome = yield from self._execute_sell_actions_for_plan(
                sell_plan,
                phase_label="Xunlai sells",
            )
            self._merge_phase_outcome(outcome, sell_outcome)
            if sell_outcome.completed <= 0:
                break
            yield from Routines.Yield.wait(100)

        return outcome

    def _execute_merchant_sell_phase(
        self,
        merchant_coords: tuple[float, float] | None,
        merchant_sell_item_ids: list[int],
    ) -> ExecutionPhaseOutcome:
        outcome = ExecutionPhaseOutcome(
            label="Merchant sells",
            measure_label="items",
            attempted=len(merchant_sell_item_ids),
        )
        if not merchant_coords or not merchant_sell_item_ids:
            return outcome

        self._debug_log(
            f"Merchant sell phase: coords={self._format_debug_coords(merchant_coords)} "
            f"item_count={len(merchant_sell_item_ids)}"
        )
        merchant_items = yield from self._open_merchant(merchant_coords)
        if not merchant_items:
            outcome.load_failures += 1
            ConsoleLog(MODULE_NAME, "Merchant inventory did not load for merchant-sell actions.", Console.MessageType.Warning)
            self._debug_log("Merchant sell phase: inventory did not load.")
            return outcome

        pre_sell_quantities = self._get_inventory_stack_quantities(merchant_sell_item_ids)
        sell_item_ids = list(pre_sell_quantities.keys())
        missing_item_count = max(0, len(merchant_sell_item_ids) - len(sell_item_ids))
        if missing_item_count > 0:
            outcome.depleted += missing_item_count
        if not sell_item_ids:
            self._debug_log("Merchant sell phase skipped send because planned item ids were no longer in inventory.")
            return outcome

        yield from Routines.Yield.Merchant.SellItems(sell_item_ids)
        confirmed_ids, pending_ids = yield from self._wait_for_merchant_sell_confirmation(pre_sell_quantities)
        outcome.completed = len(confirmed_ids)
        outcome.timeout_failures += len(pending_ids)
        if pending_ids:
            ConsoleLog(
                MODULE_NAME,
                f"Merchant sell verification timed out for {len(pending_ids)} item(s) after SellItems.",
                Console.MessageType.Warning,
            )
        self._debug_log(
            f"Merchant sell phase completed: confirmed={len(confirmed_ids)} pending={len(pending_ids)} "
            f"missing_before_send={missing_item_count}"
        )
        return outcome

    def _manual_vendor_any_merchant_groups_enabled(self) -> bool:
        return bool(
            self.auto_sell_any_merchant_normal_items
            or self.auto_sell_any_merchant_materials
            or self.auto_sell_any_merchant_runes
        )

    def _manual_vendor_settings_enabled(self) -> bool:
        return bool(
            self.auto_sell_on_manual_vendor_interaction
            or self.auto_buy_on_manual_vendor_interaction
            or (
                self.auto_sell_to_any_merchant
                and self._manual_vendor_any_merchant_groups_enabled()
            )
        )

    def _manual_vendor_blocked_by_runtime(self) -> bool:
        return bool(
            self.execution_running
            or self.travel_preview_running
            or self.identify_running
            or self.instant_destroy_running
            or self.salvage_running
            or self.storage_scan_running
            or self.auto_cleanup_running
        )

    def _format_manual_vendor_context_for_debug(self, context: ManualVendorContext) -> str:
        type_labels = [
            MERCHANT_TYPE_LABELS.get(merchant_type, merchant_type)
            for merchant_type in sorted(context.merchant_types)
        ]
        return (
            f"types={self._format_compact_list(type_labels, limit=4) or 'unknown'} "
            f"merchant_offers={len(context.merchant_item_ids)} trader_offers={len(context.trader_item_ids)} "
            f"signature={context.signature or 'none'}"
        )

    def _format_manual_vendor_modes_for_debug(self) -> str:
        modes: list[str] = []
        if self.auto_sell_on_manual_vendor_interaction:
            modes.append("auto-sell matching merchant")
        if self.auto_buy_on_manual_vendor_interaction:
            modes.append("auto-buy matching merchant")
        if self.auto_sell_to_any_merchant:
            groups: list[str] = []
            if self.auto_sell_any_merchant_normal_items:
                groups.append("normal items")
            if self.auto_sell_any_merchant_materials:
                groups.append("materials")
            if self.auto_sell_any_merchant_runes:
                groups.append("runes")
            modes.append(
                "any merchant fallback"
                + (f" ({', '.join(groups)})" if groups else " (no groups)")
            )
        return self._format_compact_list(modes, limit=4) or "none"

    def _is_merchant_window_open(self) -> bool:
        try:
            from Py4GWCoreLib.UIManager import UIManager

            frame_id = int(UIManager.GetFrameIDByHash(MERCHANT_FRAME_HASH) or 0)
            return frame_id > 0 and bool(UIManager.FrameExists(frame_id))
        except Exception:
            return False

    def _get_offered_item_ids(self, service: object) -> list[int]:
        getter = getattr(service, "GetOfferedItems", None)
        if not callable(getter):
            return []
        try:
            offered_item_ids: list[int] = []
            for raw_item_id in list(getter() or []):
                item_id = max(0, _safe_int(raw_item_id, 0))
                if item_id > 0:
                    offered_item_ids.append(item_id)
            return offered_item_ids
        except Exception:
            return []

    def _get_item_models_from_ids(self, item_ids: list[int]) -> set[int]:
        model_ids: set[int] = set()
        for item_id in item_ids:
            try:
                model_id = int(GLOBAL_CACHE.Item.GetModelID(int(item_id)))
            except Exception:
                model_id = 0
            if model_id > 0:
                model_ids.add(model_id)
        return model_ids

    def _offered_items_include_rune_stock(self, item_ids: list[int], model_ids: set[int]) -> bool:
        if int(ModelID.Rune_Of_Superior_Vigor.value) in model_ids:
            return True
        for item_id in item_ids:
            try:
                if self._get_standalone_rune_identifiers_for_item_id(int(item_id)):
                    return True
            except Exception:
                continue
        return False

    def _get_current_manual_vendor_context(self) -> ManualVendorContext:
        if not self._is_merchant_window_open():
            return ManualVendorContext()

        trading_api = getattr(GLOBAL_CACHE, "Trading", None)
        merchant_api = getattr(trading_api, "Merchant", None) if trading_api is not None else None
        trader_api = getattr(trading_api, "Trader", None) if trading_api is not None else None
        merchant_item_ids = self._get_offered_item_ids(merchant_api)
        trader_item_ids = self._get_offered_item_ids(trader_api)
        merchant_models = self._get_item_models_from_ids(merchant_item_ids)
        trader_models = self._get_item_models_from_ids(trader_item_ids)

        merchant_types: set[str] = set()
        if trader_models & COMMON_CRAFTING_MATERIAL_MODEL_IDS:
            merchant_types.add(MERCHANT_TYPE_MATERIALS)
        if trader_models & RARE_CRAFTING_MATERIAL_MODEL_IDS:
            merchant_types.add(MERCHANT_TYPE_RARE_MATERIALS)
        if any(_is_scroll_trader_stock_model(model_id) for model_id in trader_models):
            merchant_types.add(MERCHANT_TYPE_SCROLL_TRADER)
        if self._offered_items_include_rune_stock(trader_item_ids, trader_models):
            merchant_types.add(MERCHANT_TYPE_RUNE_TRADER)

        normal_merchant_stock = {
            int(ModelID.Identification_Kit.value),
            int(ModelID.Superior_Identification_Kit.value),
            int(ModelID.Salvage_Kit.value),
            int(ModelID.Salvage_Kit_preSearing.value),
            int(ModelID.Expert_Salvage_Kit.value),
            int(ModelID.Superior_Salvage_Kit.value),
            int(ModelID.Vial_Of_Dye.value),
        }
        if merchant_models & normal_merchant_stock:
            merchant_types.add(MERCHANT_TYPE_MERCHANT)
        if not merchant_types and not trader_item_ids:
            merchant_types.add(MERCHANT_TYPE_MERCHANT)

        signature_parts = [
            str(int(Map.GetMapID() or 0)),
            ",".join(sorted(merchant_types)),
            ",".join(str(model_id) for model_id in sorted(merchant_models)),
            ",".join(str(model_id) for model_id in sorted(trader_models)),
        ]
        return ManualVendorContext(
            signature="|".join(signature_parts),
            merchant_types=merchant_types,
            merchant_item_ids=merchant_item_ids,
            trader_item_ids=trader_item_ids,
        )

    def _build_manual_vendor_supported_context(
        self,
        context: ManualVendorContext,
    ) -> tuple[bool, str, dict[str, tuple[float, float] | None]]:
        del context
        return (
            True,
            "Manual merchant window is open.",
            {
                MERCHANT_TYPE_MERCHANT: (0.0, 0.0),
                MERCHANT_TYPE_MATERIALS: (0.0, 0.0),
                MERCHANT_TYPE_RARE_MATERIALS: (0.0, 0.0),
                MERCHANT_TYPE_RUNE_TRADER: (0.0, 0.0),
                MERCHANT_TYPE_SCROLL_TRADER: (0.0, 0.0),
                MERCHANT_TYPE_CONSUMABLE_CRAFTER: None,
            },
        )

    def _get_manual_merchant_sale_for_item_id(
        self,
        item_id: int,
        quantity_to_sell: int = 0,
        *,
        model_id: int = 0,
        label: str = "",
    ) -> PlannedManualMerchantSale | None:
        safe_item_id = max(0, _safe_int(item_id, 0))
        if safe_item_id <= 0:
            return None
        item = self._build_inventory_item_info(safe_item_id)
        if item is not None:
            safe_model_id = int(item.model_id)
            safe_label = str(item.name or "").strip() or self._format_model_label(safe_model_id)
        else:
            safe_model_id = max(0, _safe_int(model_id, 0))
            if safe_model_id <= 0:
                try:
                    safe_model_id = max(0, int(GLOBAL_CACHE.Item.GetModelID(safe_item_id)))
                except Exception:
                    safe_model_id = 0
            safe_label = str(label or "").strip() or self._format_model_label(safe_model_id) or f"Item {safe_item_id}"
        return PlannedManualMerchantSale(
            item_id=safe_item_id,
            model_id=safe_model_id,
            label=safe_label,
            quantity_to_sell=max(0, _safe_int(quantity_to_sell, 0)),
        )

    def _add_manual_merchant_sale(
        self,
        sales_by_item_id: dict[int, PlannedManualMerchantSale],
        sale: PlannedManualMerchantSale | None,
    ) -> None:
        if sale is None or int(sale.item_id) <= 0:
            return
        existing = sales_by_item_id.get(int(sale.item_id))
        if existing is None:
            sales_by_item_id[int(sale.item_id)] = sale
            return
        existing_quantity = max(0, int(existing.quantity_to_sell))
        next_quantity = max(0, int(sale.quantity_to_sell))
        existing.quantity_to_sell = 0 if existing_quantity <= 0 or next_quantity <= 0 else max(existing_quantity, next_quantity)

    def _get_manual_material_fallback_merchant_sell_item_ids(self, plan: PlanResult) -> set[int]:
        fallback_model_ids = {
            int(entry.model_id)
            for entry in plan.entries
            if str(entry.action_type) == "sell"
            and str(entry.merchant_type) == MERCHANT_TYPE_MERCHANT
            and str(entry.state) == PLAN_STATE_WILL_EXECUTE
            and int(entry.model_id) in ALL_CRAFTING_MATERIAL_MODEL_IDS
            and "merchant fallback" in str(entry.reason or "").casefold()
        }
        if not fallback_model_ids:
            return set()

        fallback_item_ids: set[int] = set()
        for item_id in plan.merchant_sell_item_ids:
            safe_item_id = max(0, _safe_int(item_id, 0))
            if safe_item_id <= 0:
                continue
            try:
                model_id = int(GLOBAL_CACHE.Item.GetModelID(safe_item_id))
            except Exception:
                item = self._build_inventory_item_info(safe_item_id)
                model_id = int(item.model_id) if item is not None else 0
            if model_id in fallback_model_ids:
                fallback_item_ids.add(safe_item_id)
        return fallback_item_ids

    def _get_manual_matching_merchant_sell_item_ids(self, plan: PlanResult) -> list[int]:
        trader_owned_item_ids = {
            int(sale.item_id)
            for sale in plan.material_sales
            if int(sale.item_id) > 0
        }
        trader_owned_item_ids.update(
            int(sale.item_id)
            for sale in plan.rune_trader_sales
            if int(sale.item_id) > 0
        )
        trader_owned_item_ids.update(self._get_manual_material_fallback_merchant_sell_item_ids(plan))
        return [
            int(item_id)
            for item_id in plan.merchant_sell_item_ids
            if int(item_id) > 0 and int(item_id) not in trader_owned_item_ids
        ]

    def _debug_manual_vendor_sell_filter(
        self,
        plan: PlanResult,
        matching_merchant_sell_item_ids: list[int],
        material_fallback_item_ids: set[int],
    ) -> None:
        if not self.debug_logging or not plan.merchant_sell_item_ids:
            return
        trader_sale_item_ids = {
            int(sale.item_id)
            for sale in plan.material_sales
            if int(sale.item_id) > 0
        }
        trader_sale_item_ids.update(
            int(sale.item_id)
            for sale in plan.rune_trader_sales
            if int(sale.item_id) > 0
        )
        trader_sale_item_ids.update(int(item_id) for item_id in material_fallback_item_ids)
        excluded_count = len(
            [
                item_id
                for item_id in plan.merchant_sell_item_ids
                if int(item_id) in trader_sale_item_ids
            ]
        )
        self._debug_log(
            "Manual vendor merchant-sell filter: "
            f"planned={len(plan.merchant_sell_item_ids)} matching={len(matching_merchant_sell_item_ids)} "
            f"trader_owned_or_fallback={excluded_count}"
        )
        if excluded_count <= 0:
            return
        if not self.auto_sell_to_any_merchant:
            self._debug_log(
                "Manual vendor skipped trader-targeted merchant fallback item(s) because "
                "'Also sell selected items to any merchant' is off."
            )
            return
        if material_fallback_item_ids and not self.auto_sell_any_merchant_materials:
            self._debug_log(
                "Manual vendor skipped material merchant fallback item(s) because the materials fallback group is off."
            )
        if plan.rune_trader_sales and not self.auto_sell_any_merchant_runes:
            self._debug_log(
                "Manual vendor skipped rune/insignia merchant fallback item(s) because the rune fallback group is off."
            )

    def _execute_open_merchant_sell_phase(
        self,
        manual_sales: list[PlannedManualMerchantSale],
        *,
        phase_label: str = "Merchant sells",
    ) -> ExecutionPhaseOutcome:
        outcome = ExecutionPhaseOutcome(
            label=phase_label,
            measure_label="items",
            attempted=len(manual_sales),
        )
        if not manual_sales:
            return outcome

        for sale in manual_sales:
            item_id = int(sale.item_id)
            current_quantity = max(0, int(GLOBAL_CACHE.Item.Properties.GetQuantity(item_id)))
            if current_quantity <= 0:
                outcome.depleted += 1
                continue

            requested_quantity = max(0, int(sale.quantity_to_sell))
            if requested_quantity <= 0:
                requested_quantity = current_quantity
            requested_quantity = min(requested_quantity, current_quantity)
            if requested_quantity <= 0:
                outcome.depleted += 1
                continue

            if requested_quantity < current_quantity:
                split_destination = self._find_inventory_empty_slot()
                if split_destination is None:
                    outcome.timeout_failures += 1
                    self._debug_log(
                        f"Manual merchant sale skipped {sale.label}: no empty slot to split {requested_quantity}/{current_quantity}."
                    )
                    continue
                keep_quantity = current_quantity - requested_quantity
                GLOBAL_CACHE.Inventory.MoveItem(
                    item_id,
                    int(split_destination.bag_id),
                    int(split_destination.slot),
                    keep_quantity,
                )
                updated_quantity = yield from self._wait_for_stack_quantity_target(
                    item_id,
                    requested_quantity,
                    timeout_ms=MERCHANT_SELL_CONFIRM_TIMEOUT_MS,
                    step_ms=50,
                )
                if int(updated_quantity) != requested_quantity:
                    outcome.timeout_failures += 1
                    self._debug_log(
                        f"Manual merchant sale split verification failed for {sale.label}: "
                        f"expected {requested_quantity}, observed {updated_quantity}."
                    )
                    continue
                current_quantity = updated_quantity

            value = max(0, int(GLOBAL_CACHE.Item.Properties.GetValue(item_id)))
            GLOBAL_CACHE.Trading.Merchant.SellItem(item_id, int(current_quantity) * value)
            yield from self._wait_for_action_queue_empty("MERCHANT", timeout_ms=MERCHANT_SELL_CONFIRM_TIMEOUT_MS, step_ms=50)
            confirmed_ids, pending_ids = yield from self._wait_for_merchant_sell_confirmation(
                {item_id: int(current_quantity)},
                timeout_ms=MERCHANT_SELL_CONFIRM_TIMEOUT_MS,
                step_ms=50,
            )
            if confirmed_ids and not pending_ids:
                outcome.completed += 1
            else:
                outcome.timeout_failures += 1
            yield from Routines.Yield.wait(40)

        self._debug_log(
            f"{phase_label}: completed={outcome.completed}/{outcome.attempted} "
            f"timeouts={outcome.timeout_failures} depleted={outcome.depleted}"
        )
        return outcome

    def _run_manual_vendor_pass(
        self,
        context: ManualVendorContext,
        *,
        running_already_marked: bool = False,
    ):
        if self.manual_vendor_running and not running_already_marked:
            return ExecutionPhaseOutcome(label="Manual merchant automation", measure_label="actions")
        self.manual_vendor_running = True
        self.last_error = ""
        self.last_manual_vendor_summary = ""
        paused_inventory_plus = None
        completed_any = False
        phase_summaries: list[str] = []
        try:
            yield from Routines.Yield.wait(120)
            if not self._is_merchant_window_open():
                return ExecutionPhaseOutcome(label="Manual merchant automation", measure_label="actions")

            current_context = self._get_current_manual_vendor_context()
            if current_context.signature:
                context = current_context
                self.manual_vendor_handled_signature = context.signature
            if not context.signature or not context.merchant_types:
                self._debug_log("Manual vendor automation skipped because the opened vendor type could not be detected.")
                return ExecutionPhaseOutcome(label="Manual merchant automation", measure_label="actions")

            self._debug_log(
                "Manual vendor automation start: "
                f"{self._format_manual_vendor_context_for_debug(context)} "
                f"modes={self._format_manual_vendor_modes_for_debug()}"
            )
            plan = self._build_plan(
                ignore_travel_target=True,
                allow_consumable_multi_stop=False,
                exclude_consumable_crafter=True,
                supported_context_override=self._build_manual_vendor_supported_context(context),
            )

            paused_inventory_plus = self._pause_inventory_plus()
            normal_merchant_sales: dict[int, PlannedManualMerchantSale] = {}
            material_fallback_item_ids = self._get_manual_material_fallback_merchant_sell_item_ids(plan)
            matching_merchant_sell_item_ids = self._get_manual_matching_merchant_sell_item_ids(plan)
            self._debug_manual_vendor_sell_filter(
                plan,
                matching_merchant_sell_item_ids,
                material_fallback_item_ids,
            )
            if (
                self.auto_sell_on_manual_vendor_interaction
                and MERCHANT_TYPE_MERCHANT in context.merchant_types
            ):
                for item_id in matching_merchant_sell_item_ids:
                    self._add_manual_merchant_sale(
                        normal_merchant_sales,
                        self._get_manual_merchant_sale_for_item_id(int(item_id)),
                    )

            if (
                self.auto_sell_to_any_merchant
                and MERCHANT_TYPE_MERCHANT in context.merchant_types
                and self._manual_vendor_any_merchant_groups_enabled()
            ):
                if self.auto_sell_any_merchant_normal_items:
                    for item_id in matching_merchant_sell_item_ids:
                        self._add_manual_merchant_sale(
                            normal_merchant_sales,
                            self._get_manual_merchant_sale_for_item_id(int(item_id)),
                        )
                if self.auto_sell_any_merchant_materials:
                    for sale in plan.material_sales:
                        self._add_manual_merchant_sale(
                            normal_merchant_sales,
                            self._get_manual_merchant_sale_for_item_id(
                                int(sale.item_id),
                                int(sale.quantity_to_sell),
                                model_id=int(sale.model_id),
                                label=sale.label,
                            ),
                        )
                    for item_id in material_fallback_item_ids:
                        self._add_manual_merchant_sale(
                            normal_merchant_sales,
                            self._get_manual_merchant_sale_for_item_id(int(item_id)),
                        )
                if self.auto_sell_any_merchant_runes:
                    for sale in plan.rune_trader_sales:
                        self._add_manual_merchant_sale(
                            normal_merchant_sales,
                            self._get_manual_merchant_sale_for_item_id(
                                int(sale.item_id),
                                model_id=int(sale.model_id),
                                label=sale.label,
                            ),
                        )

            if normal_merchant_sales:
                outcome = yield from self._execute_open_merchant_sell_phase(
                    list(normal_merchant_sales.values()),
                    phase_label="Merchant sells",
                )
                completed_any = completed_any or outcome.completed > 0
                summary = self._format_execution_phase_summary(outcome)
                if summary:
                    phase_summaries.append(summary)

            if self.auto_sell_on_manual_vendor_interaction:
                for merchant_type, label in (
                    (MERCHANT_TYPE_MATERIALS, "Material sales"),
                    (MERCHANT_TYPE_RARE_MATERIALS, "Rare material sales"),
                ):
                    if merchant_type not in context.merchant_types:
                        continue
                    sales = [sale for sale in plan.material_sales if sale.merchant_type == merchant_type]
                    if not sales:
                        continue
                    outcome = yield from self._sell_planned_materials(
                        (0.0, 0.0),
                        sales,
                        phase_label=label,
                        trader_items=context.trader_item_ids,
                    )
                    completed_any = completed_any or outcome.completed > 0
                    summary = self._format_execution_phase_summary(outcome)
                    if summary:
                        phase_summaries.append(summary)

                if MERCHANT_TYPE_RUNE_TRADER in context.merchant_types and plan.rune_trader_sales:
                    outcome = yield from self._sell_planned_trader_items(
                        (0.0, 0.0),
                        plan.rune_trader_sales,
                        phase_label="Rune trader sales",
                        trader_items=context.trader_item_ids,
                    )
                    completed_any = completed_any or outcome.completed > 0
                    summary = self._format_execution_phase_summary(outcome)
                    if summary:
                        phase_summaries.append(summary)

            if self.auto_buy_on_manual_vendor_interaction:
                merchant_buy_outcome = ExecutionPhaseOutcome(
                    label="Merchant buys",
                    measure_label="items",
                    attempted=sum(max(0, int(buy.quantity)) for buy in plan.merchant_stock_buys),
                )
                if MERCHANT_TYPE_MERCHANT in context.merchant_types:
                    if plan.merchant_stock_buys and not context.merchant_item_ids:
                        self._debug_log("Manual vendor auto-buy found no merchant offers loaded for merchant-stock buys.")
                    for merchant_buy in plan.merchant_stock_buys:
                        buy_result = yield from self._buy_merchant_model(
                            int(merchant_buy.model_id),
                            int(merchant_buy.quantity),
                            offered_items=context.merchant_item_ids,
                            cleanup=merchant_buy.cleanup,
                        )
                        self._merge_merchant_buy_result(
                            merchant_buy_outcome,
                            buy_result,
                            int(merchant_buy.quantity),
                        )
                    summary = self._format_execution_phase_summary(merchant_buy_outcome)
                    if summary:
                        phase_summaries.append(summary)
                    completed_any = completed_any or merchant_buy_outcome.completed > 0

                for merchant_type, label in (
                    (MERCHANT_TYPE_MATERIALS, "Material buys"),
                    (MERCHANT_TYPE_RARE_MATERIALS, "Rare material buys"),
                ):
                    if merchant_type not in context.merchant_types:
                        continue
                    buys = [buy for buy in plan.material_buys if buy.merchant_type == merchant_type]
                    if not buys:
                        continue
                    outcome = yield from self._buy_planned_materials(
                        (0.0, 0.0),
                        buys,
                        phase_label=label,
                        trader_items=context.trader_item_ids,
                    )
                    completed_any = completed_any or outcome.completed > 0
                    summary = self._format_execution_phase_summary(outcome)
                    if summary:
                        phase_summaries.append(summary)

                if MERCHANT_TYPE_RUNE_TRADER in context.merchant_types and plan.rune_trader_buys:
                    outcome = yield from self._buy_planned_rune_trader_items(
                        (0.0, 0.0),
                        plan.rune_trader_buys,
                        phase_label="Rune trader buys",
                        trader_items=context.trader_item_ids,
                    )
                    completed_any = completed_any or outcome.completed > 0
                    summary = self._format_execution_phase_summary(outcome)
                    if summary:
                        phase_summaries.append(summary)

                if MERCHANT_TYPE_SCROLL_TRADER in context.merchant_types and plan.scroll_trader_buys:
                    outcome = yield from self._buy_planned_scroll_trader_items(
                        (0.0, 0.0),
                        plan.scroll_trader_buys,
                        phase_label="Scroll trader buys",
                        trader_items=context.trader_item_ids,
                    )
                    completed_any = completed_any or outcome.completed > 0
                    summary = self._format_execution_phase_summary(outcome)
                    if summary:
                        phase_summaries.append(summary)

            self.last_manual_vendor_summary = " ".join(summary for summary in phase_summaries if summary).strip()
            if completed_any:
                self._mark_preview_dirty("Manual merchant automation finished. Preview again to refresh the plan.")
            elif self.last_manual_vendor_summary:
                self.status_message = "Manual merchant automation finished."
            if self.last_manual_vendor_summary:
                self._debug_log(self.last_manual_vendor_summary)
            return ExecutionPhaseOutcome(
                label="Manual merchant automation",
                measure_label="actions",
                attempted=len(phase_summaries),
                completed=1 if completed_any else 0,
            )
        except Exception as exc:
            self.last_error = f"{exc}"
            self.last_manual_vendor_summary = "Manual merchant automation failed. See the console log for details."
            self.status_message = self.last_manual_vendor_summary
            ConsoleLog(MODULE_NAME, f"Manual merchant automation error: {exc}", Console.MessageType.Error)
            ConsoleLog(MODULE_NAME, traceback.format_exc(), Console.MessageType.Error)
        finally:
            self.manual_vendor_running = False
            self.manual_vendor_cooldown_until_ms = int(time.time() * 1000) + MANUAL_VENDOR_COOLDOWN_MS
            if paused_inventory_plus is not None:
                paused_inventory_plus.resume()
            if not self._is_merchant_window_open():
                self.manual_vendor_handled_signature = ""
            yield

    def _update_manual_vendor_runtime(self):
        if not Map.IsMapReady():
            return
        if not self._manual_vendor_settings_enabled():
            self.manual_vendor_handled_signature = ""
            return
        if self.manual_vendor_running or self._manual_vendor_blocked_by_runtime():
            return
        if int(time.time() * 1000) < int(self.manual_vendor_cooldown_until_ms):
            return
        if not self._is_merchant_window_open():
            self.manual_vendor_handled_signature = ""
            return

        context = self._get_current_manual_vendor_context()
        if not context.signature:
            return
        if context.signature == self.manual_vendor_handled_signature:
            return

        self.manual_vendor_handled_signature = context.signature
        self.manual_vendor_running = True
        GLOBAL_CACHE.Coroutines.append(
            self._run_manual_vendor_pass(
                context,
                running_already_marked=True,
            )
        )

    def _execute_consumable_crafter_multi_stop_route(self):
        self.execution_running = True
        self.last_error = ""
        self.last_execution_summary = ""
        self.last_cleanup_summary = ""
        self.last_execution_phase_durations_ms = {}
        self._clear_preview_inventory_diff()
        self._clear_preview_projection_state()
        paused_inventory_plus = None
        phase_summaries: list[str] = []
        try:
            destination_outpost_id, destination_name = self._get_consumable_crafter_multi_stop_target()
            if destination_outpost_id <= 0:
                yield from self._execute_now(local_only=False, allow_multi_stop=False)
                return

            embark_name = self._get_embark_beach_outpost_name()
            self._invalidate_supported_context_cache()
            if not self._is_travel_target_reached(EMBARK_BEACH_MAP_ID):
                self.status_message = f"Traveling to {embark_name} for Consumable Crafter buys."
                self._debug_log(f"Multi-stop execution travel: target={embark_name} ({EMBARK_BEACH_MAP_ID})")
                travel_ok = yield from self._travel_to_target_outpost(EMBARK_BEACH_MAP_ID)
                if not travel_ok:
                    self.status_message = f"Failed to travel to {embark_name}."
                    self._debug_log(f"Multi-stop execution aborted: failed to travel to {embark_name} ({EMBARK_BEACH_MAP_ID}).")
                    return
                self._invalidate_supported_context_cache()
                yield from Routines.Yield.wait(300)

            consumable_plan = self._build_plan(
                ignore_travel_target=True,
                allow_consumable_multi_stop=False,
                consumable_crafter_only=True,
            )
            self.preview_plan = consumable_plan
            self._log_plan_summary("Multi-stop Embark plan", consumable_plan)
            if self._plan_needs_exact_storage_scan(consumable_plan):
                self.status_message = "Opening Xunlai for exact Embark Beach consumable crafting checks."
                storage_opened = yield from self._ensure_storage_open(purpose="Embark Beach consumable crafting")
                if storage_opened:
                    yield from Routines.Yield.wait(150)
                    self._invalidate_supported_context_cache()
                    consumable_plan = self._build_plan(
                        ignore_travel_target=True,
                        allow_consumable_multi_stop=False,
                        consumable_crafter_only=True,
                    )
                    self.preview_plan = consumable_plan
                    self._log_plan_summary("Multi-stop Embark storage-refreshed plan", consumable_plan)
                else:
                    phase_summaries.append("Consumable crafters were skipped because Xunlai could not be opened for exact material checks.")
                    consumable_plan.consumable_crafter_buys = []

            consumable_craft_outcome = ExecutionPhaseOutcome(label="Consumable crafters", measure_label="crafts")
            consumable_crafts_started_at = time.perf_counter()
            if consumable_plan.consumable_crafter_buys:
                paused_inventory_plus = self._pause_inventory_plus()
                if paused_inventory_plus is not None:
                    self._debug_log("Multi-stop execution: paused Inventory Plus for consumable crafting.")
                consumable_craft_outcome = yield from self._craft_planned_consumables(
                    consumable_plan.consumable_crafter_buys,
                    phase_label="Consumable crafters",
                )
            self.last_execution_phase_durations_ms["consumable_crafters"] = max(
                0.0,
                (time.perf_counter() - consumable_crafts_started_at) * 1000.0,
            )
            consumable_craft_summary = self._format_execution_phase_summary(consumable_craft_outcome)
            if consumable_craft_summary:
                phase_summaries.append(consumable_craft_summary)
            if paused_inventory_plus is not None:
                paused_inventory_plus.resume()
                paused_inventory_plus = None
                self._debug_log("Multi-stop execution: resumed Inventory Plus after consumable crafting.")

            remaining_preview = self._build_plan(
                projected_preview=True,
                projected_target_override_outpost_id=destination_outpost_id,
                allow_consumable_multi_stop=False,
                exclude_consumable_crafter=True,
            )
            self.preview_plan = remaining_preview
            if remaining_preview.has_actions:
                self.status_message = f"Traveling to {destination_name} for remaining Merchant Rules work."
                if not self._is_travel_target_reached(destination_outpost_id):
                    travel_ok = yield from self._travel_to_target_outpost(destination_outpost_id)
                    if not travel_ok:
                        self.status_message = f"Failed to travel to {destination_name}."
                        if phase_summaries:
                            self.last_execution_summary = " ".join(summary for summary in phase_summaries if summary).strip()
                        self._debug_log(
                            f"Multi-stop execution aborted: failed to travel to {destination_name} ({destination_outpost_id})."
                        )
                        return
                    self._invalidate_supported_context_cache()
                    yield from Routines.Yield.wait(300)
                yield from self._execute_now(
                    local_only=False,
                    allow_multi_stop=False,
                    exclude_consumable_crafter=True,
                )
                if self.last_error:
                    if phase_summaries:
                        combined_summary = " ".join(
                            summary
                            for summary in [*phase_summaries, self.last_execution_summary]
                            if summary
                        ).strip()
                        if combined_summary:
                            self.last_execution_summary = combined_summary
                    return
                if self.last_execution_summary:
                    phase_summaries.append(self.last_execution_summary)
            else:
                self._debug_log("Multi-stop execution: no remaining non-consumable work after Embark Beach crafting.")

            self.last_execution_summary = " ".join(summary for summary in phase_summaries if summary).strip()
            if not self.last_execution_summary:
                self.last_execution_summary = "Execution finished, but no merchant actions reported a completed or attempted outcome."
            self.status_message = "Travel + Execute finished. Preview again to refresh the post-run state."
            self.preview_ready = False
            self._debug_log(self.last_execution_summary)
        except Exception as exc:
            self.last_error = f"{exc}"
            self.status_message = "Execution failed. See the console log for details."
            ConsoleLog(MODULE_NAME, f"Execution error: {exc}", Console.MessageType.Error)
            ConsoleLog(MODULE_NAME, traceback.format_exc(), Console.MessageType.Error)
        finally:
            self.execution_running = False
            if paused_inventory_plus is not None:
                paused_inventory_plus.resume()
                self._debug_log("Multi-stop execution: resumed Inventory Plus.")
            yield

    def _execute_now(
        self,
        *,
        local_only: bool = False,
        allow_multi_stop: bool = True,
        exclude_consumable_crafter: bool = False,
    ):
        if (
            allow_multi_stop
            and not local_only
            and not exclude_consumable_crafter
            and self._should_use_consumable_crafter_multi_stop_route()
        ):
            yield from self._execute_consumable_crafter_multi_stop_route()
            return

        self.execution_running = True
        self.last_error = ""
        self.last_execution_summary = ""
        self.last_cleanup_summary = ""
        self.last_execution_phase_durations_ms = {}
        self._clear_preview_inventory_diff()
        paused_inventory_plus = None
        phase_summaries: list[str] = []
        try:
            self._invalidate_supported_context_cache()
            self._clear_preview_projection_state()
            execution_label = "Execute Here" if local_only else "Travel + Execute"
            plan = self._build_plan(
                ignore_travel_target=local_only,
                allow_consumable_multi_stop=allow_multi_stop,
                exclude_consumable_crafter=exclude_consumable_crafter,
            )
            self.preview_plan = plan
            local_availability = self._get_preview_here_availability()
            actionable_here_count, skipped_here_count = self._get_locally_actionable_preview_counts(
                plan,
                availability_here=local_availability,
            )
            self._log_plan_summary(f"{execution_label} start", plan)
            if plan.travel_to_outpost_id > 0:
                self.status_message = f"Traveling to {plan.travel_to_outpost_name} before merchant handling."
                self._debug_log(
                    f"Execution travel: target={plan.travel_to_outpost_name} ({plan.travel_to_outpost_id})"
                )
                travel_ok = yield from self._travel_to_target_outpost(plan.travel_to_outpost_id)
                if not travel_ok:
                    self.status_message = f"Failed to travel to {plan.travel_to_outpost_name}."
                    self._debug_log(
                        f"Execution aborted: failed to travel to {plan.travel_to_outpost_name} ({plan.travel_to_outpost_id})."
                    )
                    return
                self._invalidate_supported_context_cache()
                yield from Routines.Yield.wait(300)
                plan = self._build_plan(
                    allow_consumable_multi_stop=allow_multi_stop,
                    exclude_consumable_crafter=exclude_consumable_crafter,
                )
                self.preview_plan = plan
                local_availability = self._get_preview_here_availability()
                actionable_here_count, skipped_here_count = self._get_locally_actionable_preview_counts(
                    plan,
                    availability_here=local_availability,
                )
                self._clear_preview_projection_state()
                self._log_plan_summary("Execution post-travel plan", plan)
            if self._should_identify_before_execute():
                self.status_message = "Identifying selected rarities before merchant handling."
                identify_started_at = time.perf_counter()
                identify_outcome = yield from self._run_identify_pass(
                    mark_preview_dirty=False,
                    summary_subject="Identify before Execute",
                )
                self.last_execution_phase_durations_ms["identifies"] = max(0.0, (time.perf_counter() - identify_started_at) * 1000.0)
                identify_summary = self.last_identify_summary or self._format_identify_summary(
                    identify_outcome,
                    {},
                    subject="Identify before Execute",
                )
                if identify_summary:
                    phase_summaries.append(identify_summary)
                if identify_outcome.timeout_failures > 0:
                    self.last_execution_summary = " ".join(summary for summary in phase_summaries if summary).strip()
                    self.status_message = "Identify before Execute did not finish safely; merchant actions were not run."
                    if identify_outcome.completed > 0 or identify_outcome.depleted > 0:
                        self.preview_ready = False
                    self._debug_log("Execution aborted: Identify before Execute had timeout/failure results.")
                    return
                if identify_outcome.attempted > 0 or identify_outcome.completed > 0 or identify_outcome.depleted > 0 or identify_outcome.unavailable > 0:
                    yield from Routines.Yield.wait(150)
                    self._invalidate_supported_context_cache()
                    plan = self._build_plan(
                        ignore_travel_target=local_only,
                        allow_consumable_multi_stop=allow_multi_stop,
                        exclude_consumable_crafter=exclude_consumable_crafter,
                    )
                    self.preview_plan = plan
                    local_availability = self._get_preview_here_availability()
                    actionable_here_count, skipped_here_count = self._get_locally_actionable_preview_counts(
                        plan,
                        availability_here=local_availability,
                    )
                    self._clear_preview_projection_state()
                    self._log_plan_summary("Execution post-identify plan", plan)
            if not plan.supported_map:
                if (
                    not self._plan_has_local_identify_actions(plan)
                    and not self._plan_has_local_destroy_actions(plan)
                    and not self._plan_has_local_storage_actions(plan)
                ):
                    self.status_message = plan.supported_reason
                    self._debug_log(f"Execution aborted: unsupported map. {plan.supported_reason}")
                    return
                if (
                    self._plan_has_local_identify_actions(plan)
                    and self._plan_has_local_destroy_actions(plan)
                    and self._plan_has_local_storage_actions(plan)
                ):
                    self._debug_log(
                        f"Execution continuing with local identify, local destroy actions, and Xunlai deposits on unsupported map. {plan.supported_reason}"
                    )
                elif self._plan_has_local_identify_actions(plan) and self._plan_has_local_destroy_actions(plan):
                    self._debug_log(
                        f"Execution continuing with local identify and destroy actions on unsupported map. {plan.supported_reason}"
                    )
                elif self._plan_has_local_identify_actions(plan) and self._plan_has_local_storage_actions(plan):
                    self._debug_log(
                        f"Execution continuing with local identify and Xunlai deposits on unsupported map. {plan.supported_reason}"
                    )
                elif self._plan_has_local_destroy_actions(plan) and self._plan_has_local_storage_actions(plan):
                    self._debug_log(
                        f"Execution continuing with local destroy actions and Xunlai deposits on unsupported map. {plan.supported_reason}"
                    )
                elif self._plan_has_local_identify_actions(plan):
                    self._debug_log(
                        f"Execution continuing with local identify actions on unsupported map. {plan.supported_reason}"
                    )
                elif self._plan_has_local_destroy_actions(plan):
                    self._debug_log(
                        f"Execution continuing with local destroy actions on unsupported map. {plan.supported_reason}"
                    )
                else:
                    self._debug_log(
                        f"Execution continuing with Xunlai deposits on unsupported map. {plan.supported_reason}"
                    )
            storage_scan_failed = False
            storage_available_here = bool(local_availability.get(MERCHANT_TYPE_STORAGE, False))
            if self._plan_needs_exact_storage_scan(plan):
                storage_opened = False
                if local_only and not storage_available_here:
                    storage_scan_failed = True
                    phase_summaries.append("Rune trader buys were skipped because Xunlai is not available here.")
                else:
                    self.status_message = "Opening Xunlai for exact storage-aware execution."
                    storage_opened = yield from self._ensure_storage_open(purpose="storage-aware execution")
                if storage_opened:
                    yield from Routines.Yield.wait(150)
                    self._invalidate_supported_context_cache()
                    plan = self._build_plan(
                        ignore_travel_target=local_only,
                        allow_consumable_multi_stop=allow_multi_stop,
                        exclude_consumable_crafter=exclude_consumable_crafter,
                    )
                    self.preview_plan = plan
                    local_availability = self._get_preview_here_availability()
                    actionable_here_count, skipped_here_count = self._get_locally_actionable_preview_counts(
                        plan,
                        availability_here=local_availability,
                    )
                    storage_available_here = bool(local_availability.get(MERCHANT_TYPE_STORAGE, False))
                    self._clear_preview_projection_state()
                    self._log_plan_summary("Execution storage-refreshed plan", plan)
                elif not storage_scan_failed:
                    storage_scan_failed = True
                    phase_summaries.append("Storage-aware rune planning was skipped because Xunlai could not be opened.")
                    ConsoleLog(
                        MODULE_NAME,
                        "Could not open Xunlai for exact storage-aware execution; continuing with other runnable actions.",
                        Console.MessageType.Warning,
                    )
                    has_other_runnable_actions = bool(
                        plan.destroy_actions
                        or plan.destroy_item_ids
                        or plan.merchant_stock_buys
                        or plan.material_buys
                        or plan.material_sales
                        or plan.merchant_sell_item_ids
                        or plan.rune_trader_sales
                        or plan.scroll_trader_buys
                    )
                    if not has_other_runnable_actions:
                        self.status_message = "Could not open Xunlai for exact storage-aware execution."
                        self._debug_log("Execution aborted: exact storage-aware rune planning required Xunlai, but it could not be opened.")
                        return
            if not plan.has_actions:
                if storage_scan_failed:
                    self.status_message = "Could not open Xunlai for exact storage-aware execution."
                else:
                    self.status_message = "Nothing to execute for the current rules and inventory state."
                self._debug_log("Execution aborted: no actionable work in the current plan.")
                return

            paused_inventory_plus = self._pause_inventory_plus()
            if paused_inventory_plus is not None:
                self._debug_log("Execution: paused Inventory Plus for merchant handling.")

            merchant_coords = plan.coords.get(MERCHANT_TYPE_MERCHANT)
            destroy_started_at = time.perf_counter()
            destroy_outcome = yield from self._execute_destroy_phase(plan.destroy_actions or plan.destroy_item_ids)
            self.last_execution_phase_durations_ms["destroys"] = max(0.0, (time.perf_counter() - destroy_started_at) * 1000.0)
            destroy_summary = self._format_execution_phase_summary(destroy_outcome)
            if destroy_summary:
                phase_summaries.append(destroy_summary)

            xunlai_prefetch_outcome = ExecutionPhaseOutcome(label="Xunlai sell pre-pull", measure_label="items")
            xunlai_prefetch_started_at = time.perf_counter()
            if self._has_ready_xunlai_sell_rules():
                xunlai_prefetch_outcome = yield from self._execute_xunlai_sell_withdraw_phase(
                    plan,
                    local_only=local_only,
                    storage_available_here=storage_available_here,
                )
                if xunlai_prefetch_outcome.completed > 0:
                    yield from Routines.Yield.wait(150)
                    self._invalidate_supported_context_cache()
                    plan = self._build_plan(
                        ignore_travel_target=local_only,
                        allow_consumable_multi_stop=allow_multi_stop,
                        exclude_consumable_crafter=exclude_consumable_crafter,
                    )
                    self.preview_plan = plan
                    local_availability = self._get_preview_here_availability()
                    actionable_here_count, skipped_here_count = self._get_locally_actionable_preview_counts(
                        plan,
                        availability_here=local_availability,
                    )
                    storage_available_here = bool(local_availability.get(MERCHANT_TYPE_STORAGE, False))
                    merchant_coords = plan.coords.get(MERCHANT_TYPE_MERCHANT)
                    self._clear_preview_projection_state()
                    self._log_plan_summary("Execution post-Xunlai pre-pull plan", plan)
            self.last_execution_phase_durations_ms["xunlai_sell_prefetch"] = max(
                0.0,
                (time.perf_counter() - xunlai_prefetch_started_at) * 1000.0,
            )
            xunlai_prefetch_summary = self._format_execution_phase_summary(xunlai_prefetch_outcome)
            if xunlai_prefetch_summary:
                phase_summaries.append(xunlai_prefetch_summary)

            material_coords = plan.coords.get(MERCHANT_TYPE_MATERIALS)
            common_material_sales = [sale for sale in plan.material_sales if sale.merchant_type == MERCHANT_TYPE_MATERIALS]
            material_sale_outcome = ExecutionPhaseOutcome(label="Material sales", measure_label="trades")
            material_sales_started_at = time.perf_counter()
            if material_coords and common_material_sales:
                material_sale_outcome = yield from self._sell_planned_materials(
                    material_coords,
                    common_material_sales,
                    phase_label="Material sales",
                )
            self.last_execution_phase_durations_ms["material_sales"] = max(0.0, (time.perf_counter() - material_sales_started_at) * 1000.0)
            material_sale_summary = self._format_execution_phase_summary(material_sale_outcome)
            if material_sale_summary:
                phase_summaries.append(material_sale_summary)

            rare_material_coords = plan.coords.get(MERCHANT_TYPE_RARE_MATERIALS)
            rare_material_sales = [sale for sale in plan.material_sales if sale.merchant_type == MERCHANT_TYPE_RARE_MATERIALS]
            rare_material_sale_outcome = ExecutionPhaseOutcome(label="Rare material sales", measure_label="trades")
            rare_material_sales_started_at = time.perf_counter()
            if rare_material_coords and rare_material_sales:
                rare_material_sale_outcome = yield from self._sell_planned_materials(
                    rare_material_coords,
                    rare_material_sales,
                    phase_label="Rare material sales",
                )
            self.last_execution_phase_durations_ms["rare_material_sales"] = max(0.0, (time.perf_counter() - rare_material_sales_started_at) * 1000.0)
            rare_material_sale_summary = self._format_execution_phase_summary(rare_material_sale_outcome)
            if rare_material_sale_summary:
                phase_summaries.append(rare_material_sale_summary)

            merchant_sell_started_at = time.perf_counter()
            merchant_sell_outcome = yield from self._execute_merchant_sell_phase(merchant_coords, plan.merchant_sell_item_ids)
            self.last_execution_phase_durations_ms["merchant_sells"] = max(0.0, (time.perf_counter() - merchant_sell_started_at) * 1000.0)
            merchant_sell_summary = self._format_execution_phase_summary(merchant_sell_outcome)
            if merchant_sell_summary:
                phase_summaries.append(merchant_sell_summary)

            rune_trader_coords = plan.coords.get(MERCHANT_TYPE_RUNE_TRADER)
            rune_sale_outcome = ExecutionPhaseOutcome(label="Rune trader sales", measure_label="items")
            rune_sales_started_at = time.perf_counter()
            if rune_trader_coords and plan.rune_trader_sales:
                rune_sale_outcome = yield from self._sell_planned_trader_items(
                    rune_trader_coords,
                    plan.rune_trader_sales,
                    phase_label="Rune trader sales",
                )
            self.last_execution_phase_durations_ms["rune_sales"] = max(0.0, (time.perf_counter() - rune_sales_started_at) * 1000.0)
            rune_sale_summary = self._format_execution_phase_summary(rune_sale_outcome)
            if rune_sale_summary:
                phase_summaries.append(rune_sale_summary)

            xunlai_sell_started_at = time.perf_counter()
            xunlai_sell_outcome = ExecutionPhaseOutcome(label="Xunlai sells", measure_label="sell action(s)")
            if xunlai_prefetch_outcome.timeout_failures > 0:
                xunlai_sell_outcome = yield from self._execute_xunlai_sell_phase(
                    plan,
                    local_only=local_only,
                    storage_available_here=storage_available_here,
                )
            self.last_execution_phase_durations_ms["xunlai_sells"] = max(0.0, (time.perf_counter() - xunlai_sell_started_at) * 1000.0)
            xunlai_sell_summary = self._format_execution_phase_summary(xunlai_sell_outcome)
            if xunlai_sell_summary:
                phase_summaries.append(xunlai_sell_summary)

            storage_withdraw_transfers = [
                transfer
                for transfer in plan.storage_transfers
                if str(transfer.direction) == STORAGE_TRANSFER_WITHDRAW
            ]
            storage_transfer_outcome = ExecutionPhaseOutcome(label="Storage withdraws", measure_label="items")
            storage_transfers_started_at = time.perf_counter()
            storage_transfer_ready = not bool(storage_withdraw_transfers)
            if storage_withdraw_transfers:
                storage_ready = self._is_storage_open()
                if not storage_ready and local_only and not storage_available_here:
                    storage_transfer_outcome.load_failures += 1
                    phase_summaries.append("Rune trader buys were skipped because Xunlai is not available here.")
                    plan.rune_trader_buys = []
                elif not storage_ready:
                    storage_ready = yield from self._ensure_storage_open(purpose="planned storage transfers")
                if storage_ready:
                    storage_transfer_ready = True
                    storage_transfer_outcome = yield from self._execute_storage_transfers(
                        storage_withdraw_transfers,
                        phase_label="Storage withdraws",
                    )
                    yield from Routines.Yield.wait(100)
                    self._invalidate_supported_context_cache()
                    plan = self._build_plan(
                        ignore_travel_target=local_only,
                        allow_consumable_multi_stop=allow_multi_stop,
                        exclude_consumable_crafter=exclude_consumable_crafter,
                    )
                    self.preview_plan = plan
                    local_availability = self._get_preview_here_availability()
                    actionable_here_count, skipped_here_count = self._get_locally_actionable_preview_counts(
                        plan,
                        availability_here=local_availability,
                    )
                    storage_available_here = bool(local_availability.get(MERCHANT_TYPE_STORAGE, False))
                    self._clear_preview_projection_state()
                    self._log_plan_summary("Execution post-storage plan", plan)
                    rune_trader_coords = plan.coords.get(MERCHANT_TYPE_RUNE_TRADER)
                else:
                    storage_transfer_outcome.load_failures += 1
                    ConsoleLog(
                        MODULE_NAME,
                        "Could not open Xunlai for planned storage transfers.",
                        Console.MessageType.Warning,
                    )
                    phase_summaries.append("Rune trader buys were skipped because planned Xunlai transfers could not be completed.")
                    plan.rune_trader_buys = []
            self.last_execution_phase_durations_ms["storage_transfers"] = max(0.0, (time.perf_counter() - storage_transfers_started_at) * 1000.0)
            storage_transfer_summary = self._format_execution_phase_summary(storage_transfer_outcome)
            if storage_transfer_summary:
                phase_summaries.append(storage_transfer_summary)

            rune_buy_outcome = ExecutionPhaseOutcome(label="Rune trader buys", measure_label="items")
            rune_buys_started_at = time.perf_counter()
            if storage_transfer_ready and rune_trader_coords and plan.rune_trader_buys:
                rune_buy_outcome = yield from self._buy_planned_rune_trader_items(
                    rune_trader_coords,
                    plan.rune_trader_buys,
                    phase_label="Rune trader buys",
                )
            self.last_execution_phase_durations_ms["rune_buys"] = max(0.0, (time.perf_counter() - rune_buys_started_at) * 1000.0)
            rune_buy_summary = self._format_execution_phase_summary(rune_buy_outcome)
            if rune_buy_summary:
                phase_summaries.append(rune_buy_summary)

            scroll_trader_coords = plan.coords.get(MERCHANT_TYPE_SCROLL_TRADER)
            scroll_buy_outcome = ExecutionPhaseOutcome(label="Scroll trader buys", measure_label="items")
            scroll_buys_started_at = time.perf_counter()
            if scroll_trader_coords and plan.scroll_trader_buys:
                scroll_buy_outcome = yield from self._buy_planned_scroll_trader_items(
                    scroll_trader_coords,
                    plan.scroll_trader_buys,
                    phase_label="Scroll trader buys",
                )
            self.last_execution_phase_durations_ms["scroll_buys"] = max(0.0, (time.perf_counter() - scroll_buys_started_at) * 1000.0)
            scroll_buy_summary = self._format_execution_phase_summary(scroll_buy_outcome)
            if scroll_buy_summary:
                phase_summaries.append(scroll_buy_summary)

            consumable_craft_outcome = ExecutionPhaseOutcome(label="Consumable crafters", measure_label="crafts")
            consumable_crafts_started_at = time.perf_counter()
            if plan.consumable_crafter_buys:
                consumable_craft_outcome = yield from self._craft_planned_consumables(
                    plan.consumable_crafter_buys,
                    phase_label="Consumable crafters",
                )
            self.last_execution_phase_durations_ms["consumable_crafters"] = max(0.0, (time.perf_counter() - consumable_crafts_started_at) * 1000.0)
            consumable_craft_summary = self._format_execution_phase_summary(consumable_craft_outcome)
            if consumable_craft_summary:
                phase_summaries.append(consumable_craft_summary)

            merchant_buy_outcome = ExecutionPhaseOutcome(
                label="Merchant stock",
                measure_label="items",
                attempted=sum(max(0, int(buy.quantity)) for buy in plan.merchant_stock_buys),
            )
            merchant_buy_started_at = time.perf_counter()
            if merchant_coords and plan.merchant_stock_buys:
                self._debug_log(
                    f"Merchant buy phase: coords={self._format_debug_coords(merchant_coords)} "
                    f"stock_targets={len(plan.merchant_stock_buys)}"
                )
                merchant_items = yield from self._open_merchant(merchant_coords)
                if merchant_items:
                    for merchant_buy in plan.merchant_stock_buys:
                        buy_result = yield from self._buy_merchant_model(
                            merchant_buy.model_id,
                            merchant_buy.quantity,
                            offered_items=merchant_items,
                            cleanup=merchant_buy.cleanup,
                        )
                        self._merge_merchant_buy_result(
                            merchant_buy_outcome,
                            buy_result,
                            int(merchant_buy.quantity),
                        )
                        if (
                            isinstance(buy_result, ExecutionPhaseOutcome)
                            and buy_result.completed <= 0
                            and buy_result.unavailable > 0
                        ):
                            ConsoleLog(
                                MODULE_NAME,
                                f"Merchant stock target {merchant_buy.model_id} was not offered by the merchant.",
                                Console.MessageType.Warning,
                            )
                else:
                    merchant_buy_outcome.load_failures += 1
                    ConsoleLog(MODULE_NAME, "Merchant inventory did not load for merchant-buy actions.", Console.MessageType.Warning)
                    self._debug_log("Merchant buy phase: inventory did not load.")
            self.last_execution_phase_durations_ms["merchant_stock"] = max(0.0, (time.perf_counter() - merchant_buy_started_at) * 1000.0)
            merchant_buy_summary = self._format_execution_phase_summary(merchant_buy_outcome)
            if merchant_buy_summary:
                phase_summaries.append(merchant_buy_summary)

            common_material_buys = [buy for buy in plan.material_buys if buy.merchant_type == MERCHANT_TYPE_MATERIALS]
            common_buy_outcome = ExecutionPhaseOutcome(label="Material buys", measure_label="trades")
            common_buys_started_at = time.perf_counter()
            if material_coords and common_material_buys:
                self._debug_log(
                    f"Material trader buy phase: coords={self._format_debug_coords(material_coords)} "
                    f"buy_targets={len(common_material_buys)}"
                )
                common_buy_outcome = yield from self._buy_planned_materials(
                    material_coords,
                    common_material_buys,
                    phase_label="Material buys",
                )
            self.last_execution_phase_durations_ms["material_buys"] = max(0.0, (time.perf_counter() - common_buys_started_at) * 1000.0)
            common_buy_summary = self._format_execution_phase_summary(common_buy_outcome)
            if common_buy_summary:
                phase_summaries.append(common_buy_summary)

            rare_coords = plan.coords.get(MERCHANT_TYPE_RARE_MATERIALS)
            rare_material_buys = [buy for buy in plan.material_buys if buy.merchant_type == MERCHANT_TYPE_RARE_MATERIALS]
            rare_buy_outcome = ExecutionPhaseOutcome(label="Rare material buys", measure_label="trades")
            rare_buys_started_at = time.perf_counter()
            if rare_coords and rare_material_buys:
                self._debug_log(
                    f"Rare material trader buy phase: coords={self._format_debug_coords(rare_coords)} "
                    f"buy_targets={len(rare_material_buys)}"
                )
                rare_buy_outcome = yield from self._buy_planned_materials(
                    rare_coords,
                    rare_material_buys,
                    phase_label="Rare material buys",
                )
            self.last_execution_phase_durations_ms["rare_material_buys"] = max(0.0, (time.perf_counter() - rare_buys_started_at) * 1000.0)
            rare_buy_summary = self._format_execution_phase_summary(rare_buy_outcome)
            if rare_buy_summary:
                phase_summaries.append(rare_buy_summary)

            cleanup_outcome = ExecutionPhaseOutcome(label="Xunlai Deposits", measure_label="items")
            cleanup_started_at = time.perf_counter()
            cleanup_transfers = list(plan.cleanup_transfers)
            if cleanup_transfers:
                storage_ready = self._is_storage_open()
                if not storage_ready and local_only and not storage_available_here:
                    cleanup_outcome.load_failures += 1
                    phase_summaries.append("Planned Xunlai deposits were skipped because Xunlai is not available here.")
                elif not storage_ready:
                    storage_ready = yield from self._ensure_storage_open(purpose="planned Xunlai deposits")
                if storage_ready:
                    yield from Routines.Yield.wait(150)
                    self._invalidate_supported_context_cache()
                    refreshed_cleanup_plan = self._build_plan(cleanup_only=True)
                    cleanup_transfers = list(refreshed_cleanup_plan.cleanup_transfers)
                    self._debug_log(
                        f"Storage deposits refreshed live cleanup plan: transfers={len(cleanup_transfers)} "
                        f"planned_items={sum(max(0, int(transfer.quantity)) for transfer in cleanup_transfers)}"
                    )
                if storage_ready and cleanup_transfers:
                    cleanup_outcome = yield from self._execute_storage_transfers(
                        cleanup_transfers,
                        phase_label="Storage deposits",
                    )
                elif not storage_ready:
                    cleanup_outcome.load_failures += 1
                    ConsoleLog(
                        MODULE_NAME,
                        "Could not open Xunlai for planned deposit transfers.",
                        Console.MessageType.Warning,
                    )
                    phase_summaries.append("Planned Xunlai deposits were skipped because Xunlai could not be opened.")
            self.last_execution_phase_durations_ms["cleanup_deposits"] = max(0.0, (time.perf_counter() - cleanup_started_at) * 1000.0)
            cleanup_summary = self._format_execution_phase_summary(cleanup_outcome)
            if cleanup_summary:
                self.last_cleanup_summary = cleanup_summary
                phase_summaries.append(cleanup_summary)

            if local_only:
                phase_summaries.insert(
                    0,
                    f"Execute Here: {actionable_here_count} local action(s) | {skipped_here_count} skipped / unavailable.",
                )
            self.last_execution_summary = " ".join(summary for summary in phase_summaries if summary).strip()
            if not self.last_execution_summary:
                self.last_execution_summary = "Execution finished, but no merchant actions reported a completed or attempted outcome."
            self.status_message = (
                "Execute Here finished. Preview again to refresh the post-run state."
                if local_only
                else "Travel + Execute finished. Preview again to refresh the post-run state."
            )
            self.preview_ready = False
            self._debug_log(self.last_execution_summary)
        except Exception as exc:
            self.last_error = f"{exc}"
            self.status_message = "Execution failed. See the console log for details."
            ConsoleLog(MODULE_NAME, f"Execution error: {exc}", Console.MessageType.Error)
            ConsoleLog(MODULE_NAME, traceback.format_exc(), Console.MessageType.Error)
        finally:
            self.execution_running = False
            if paused_inventory_plus is not None:
                paused_inventory_plus.resume()
                self._debug_log("Execution: resumed Inventory Plus.")
            yield

    def _execute_cleanup_now(self, *, auto_triggered: bool = False):
        self.auto_cleanup_running = True
        self.last_error = ""
        self.last_cleanup_summary = ""
        paused_inventory_plus = None
        try:
            self._invalidate_supported_context_cache()
            plan = self._build_plan(cleanup_only=True)
            if not plan.cleanup_transfers:
                self.last_cleanup_summary = (
                    "Auto deposits found nothing to move."
                    if auto_triggered
                    else "Xunlai Deposits found nothing to move."
                )
                self.status_message = self.last_cleanup_summary
                return

            paused_inventory_plus = self._pause_inventory_plus()
            if paused_inventory_plus is not None:
                self._debug_log("Xunlai Deposits: paused Inventory Plus.")

            storage_ready = self._is_storage_open()
            if not storage_ready:
                self.status_message = "Opening Xunlai for deposits."
                storage_ready = yield from self._ensure_storage_open(purpose="planned Xunlai deposits")

            cleanup_outcome = ExecutionPhaseOutcome(label="Xunlai Deposits", measure_label="items")
            if storage_ready:
                yield from Routines.Yield.wait(150)
                self._invalidate_supported_context_cache()
                plan = self._build_plan(cleanup_only=True)
                self._debug_log(
                    f"Xunlai Deposits: refreshed live cleanup plan: transfers={len(plan.cleanup_transfers)} "
                    f"planned_items={sum(max(0, int(transfer.quantity)) for transfer in plan.cleanup_transfers)}"
                )
            if storage_ready and plan.cleanup_transfers:
                cleanup_outcome = yield from self._execute_storage_transfers(
                    plan.cleanup_transfers,
                    phase_label="Xunlai Deposits",
                )
            elif not storage_ready:
                cleanup_outcome.load_failures += 1
                ConsoleLog(
                    MODULE_NAME,
                    "Could not open Xunlai for deposit transfers.",
                    Console.MessageType.Warning,
                )

            cleanup_summary = self._format_execution_phase_summary(cleanup_outcome)
            if cleanup_summary:
                self.last_cleanup_summary = cleanup_summary
            elif cleanup_outcome.completed > 0:
                self.last_cleanup_summary = f"Xunlai Deposits moved {cleanup_outcome.completed} item(s)."
            else:
                self.last_cleanup_summary = (
                    "Auto deposits found nothing to move."
                    if auto_triggered
                    else "Xunlai Deposits found nothing to move."
                )

            if cleanup_outcome.completed > 0:
                self._mark_preview_dirty()
            self.status_message = self.last_cleanup_summary
            self._debug_log(self.last_cleanup_summary)
        except Exception as exc:
            self.last_error = f"{exc}"
            self.last_cleanup_summary = "Xunlai Deposits failed. See the console log for details."
            self.status_message = self.last_cleanup_summary
            ConsoleLog(MODULE_NAME, f"Xunlai Deposits error: {exc}", Console.MessageType.Error)
            ConsoleLog(MODULE_NAME, traceback.format_exc(), Console.MessageType.Error)
        finally:
            self.auto_cleanup_running = False
            if paused_inventory_plus is not None:
                paused_inventory_plus.resume()
                self._debug_log("Xunlai Deposits: resumed Inventory Plus.")
            yield

    def _update_auto_cleanup_runtime(self):
        if not Map.IsMapReady():
            return
        if not self.auto_cleanup_on_outpost_entry or not self._has_cleanup_sources():
            return
        if not (Map.IsOutpost() or Map.IsGuildHall()):
            return
        if (
            self.execution_running
            or self.travel_preview_running
            or self.identify_running
            or self.instant_destroy_running
            or self.salvage_running
            or self.storage_scan_running
            or self.auto_cleanup_running
            or self.manual_vendor_running
        ):
            return
        if self.auto_cleanup_zone_attempted:
            return

        self.auto_cleanup_zone_attempted = True
        self._queue_cleanup_now(auto_triggered=True)

    def _get_inventory_signature(self, items: list[InventoryItemInfo] | None = None) -> tuple[tuple[int, int], ...]:
        if items is None:
            return tuple(
                sorted(
                    (
                        int(item_id),
                        max(0, int(GLOBAL_CACHE.Item.Properties.GetQuantity(item_id))),
                    )
                    for item_id in self._get_inventory_item_ids()
                    if int(item_id) > 0
                )
            )
        return tuple(
            sorted(
                (
                    int(item.item_id),
                    max(0, int(item.quantity)),
                )
                for item in items
                if int(item.item_id) > 0
            )
        )

    def _format_identify_summary(
        self,
        outcome: ExecutionPhaseOutcome,
        blocked_counts: dict[str, int],
        *,
        subject: str = "Identify",
    ) -> str:
        parts: list[str] = []
        if outcome.completed > 0:
            parts.append(f"{subject} processed {outcome.completed} item(s).")
        elif outcome.attempted > 0:
            parts.append(f"{subject} found matching items, but none were confirmed identified.")
        else:
            parts.append(f"{subject} found no matching unidentified items.")
        if outcome.timeout_failures > 0:
            parts.append(f"{outcome.timeout_failures} identify timeout/failure(s).")
        if outcome.depleted > 0:
            parts.append(f"{outcome.depleted} item(s) were already gone.")
        for reason, count in sorted(blocked_counts.items()):
            if count > 0:
                parts.append(f"Skipped {count} {reason}.")
        return " ".join(parts)

    def _identify_one_item(self, item: InventoryItemInfo):
        from Py4GWCoreLib.Inventory import Inventory

        live_item = self._build_inventory_item_info(int(item.item_id))
        if live_item is None:
            return "missing_item"
        if bool(live_item.identified):
            return "identified"

        selection_reason = self._get_identify_selection_reason(live_item)
        if not selection_reason:
            self._debug_log(f"MR Identify recheck skipped {live_item.name} ({live_item.item_id}): no longer selected.")
            return "blocked"

        id_kit_id = self._get_id_kit_id()
        if id_kit_id <= 0:
            self._debug_log(f"MR Identify skipped {live_item.name} ({live_item.item_id}): no ID kit found.")
            return "no_kit"

        item_id = int(live_item.item_id)
        self.inventory_modifier_cache.pop(item_id, None)
        self._debug_log(
            f"MR Identify starting {live_item.name} ({item_id}) using ID kit {int(id_kit_id)}; {selection_reason}."
        )

        ActionQueueManager().AddAction("IDENTIFY", Inventory.IdentifyItem, item_id, int(id_kit_id))
        queue_drained = yield from self._wait_for_action_queue_empty("IDENTIFY", timeout_ms=5000, step_ms=50)
        if not queue_drained:
            ConsoleLog(MODULE_NAME, f"MR Identify timed out starting item {item_id}.", Console.MessageType.Warning)
            return "failed"

        waited_ms = 0
        while waited_ms <= IDENTIFY_CONFIRM_TIMEOUT_MS:
            yield from Routines.Yield.wait(50)
            waited_ms += 50
            if item_id not in set(self._get_inventory_item_ids()):
                self._debug_log(f"MR Identify stopped tracking {live_item.name} ({item_id}); item left inventory.")
                return "missing_item"
            current_item = self._build_inventory_item_info(item_id)
            if current_item is not None and bool(current_item.identified):
                self.inventory_modifier_cache.pop(item_id, None)
                self._debug_log(f"MR Identify completed {current_item.name} ({item_id}).")
                return "identified"

        ConsoleLog(MODULE_NAME, f"MR Identify timed out waiting for item {item_id} to become identified.", Console.MessageType.Warning)
        return "failed"

    def _run_identify_pass(
        self,
        *,
        auto_triggered: bool = False,
        running_already_marked: bool = False,
        mark_preview_dirty: bool = True,
        summary_subject: str = "Identify",
    ):
        if self.identify_running and not running_already_marked:
            return ExecutionPhaseOutcome(label=summary_subject, measure_label="items")
        self.identify_running = True
        self.last_error = ""
        self.last_identify_summary = ""
        paused_inventory_plus = None
        outcome = ExecutionPhaseOutcome(label=summary_subject, measure_label="items")
        blocked_counts: dict[str, int] = {}
        try:
            settings = _normalize_identify_settings(self.identify_settings)
            if auto_triggered and not bool(settings.on_inventory_change):
                return outcome
            if not self._has_enabled_identify_settings():
                blocked_counts["item(s): no rarity selector enabled"] = 1
                self.last_identify_summary = self._format_identify_summary(
                    outcome,
                    blocked_counts,
                    subject=summary_subject,
                )
                self.status_message = self.last_identify_summary
                return outcome

            items = self._collect_inventory_items()
            self.identify_last_signature = self._get_inventory_signature(items)
            candidates = self._collect_identify_candidates(items)
            outcome.attempted = len(candidates)
            if not candidates:
                self.last_identify_summary = self._format_identify_summary(
                    outcome,
                    blocked_counts,
                    subject=summary_subject,
                )
                self.status_message = self.last_identify_summary
                self._debug_log(self.last_identify_summary)
                return outcome

            paused_inventory_plus = self._pause_inventory_plus()
            if paused_inventory_plus is not None:
                self._debug_log("MR Identify: paused Inventory Plus.")

            for candidate in candidates:
                status = yield from self._identify_one_item(candidate)
                if status == "identified":
                    outcome.completed += 1
                    continue
                if status == "missing_item":
                    outcome.depleted += 1
                    continue
                if status == "no_kit":
                    outcome.unavailable += 1
                    blocked_counts["item(s): no ID kit"] = blocked_counts.get("item(s): no ID kit", 0) + 1
                    continue
                if status == "blocked":
                    outcome.unavailable += 1
                    blocked_counts["item(s): no longer match selected rarity"] = (
                        blocked_counts.get("item(s): no longer match selected rarity", 0) + 1
                    )
                    continue
                outcome.timeout_failures += 1

            self.last_identify_summary = self._format_identify_summary(
                outcome,
                blocked_counts,
                subject=summary_subject,
            )
            self.status_message = self.last_identify_summary
            self._debug_log(self.last_identify_summary)
            ConsoleLog(MODULE_NAME, self.last_identify_summary, Console.MessageType.Info)
            if outcome.completed > 0:
                self._request_salvage_rescan()
                if self._is_destroy_auto_enabled():
                    self._request_instant_destroy_rescan()
                if mark_preview_dirty:
                    self._mark_preview_dirty("Inventory changed due to MR Identify. Preview again before execution.")
        except Exception as exc:
            self.last_error = f"{exc}"
            self.last_identify_summary = "MR Identify failed. See the console log for details."
            self.status_message = self.last_identify_summary
            ConsoleLog(MODULE_NAME, f"MR Identify error: {exc}", Console.MessageType.Error)
            ConsoleLog(MODULE_NAME, traceback.format_exc(), Console.MessageType.Error)
            outcome.timeout_failures += 1
        finally:
            if paused_inventory_plus is not None:
                paused_inventory_plus.resume()
                self._debug_log("MR Identify: resumed Inventory Plus.")
            self.identify_running = False
            self.identify_rescan_requested = False
            self.identify_poll_timer.Reset()
            self.identify_last_signature = self._get_inventory_signature()
            yield
        return outcome

    def _request_identify_rescan(self):
        self.identify_rescan_requested = True

    def _update_identify_runtime(self):
        if not Map.IsMapReady():
            return
        if (
            self.execution_running
            or self.travel_preview_running
            or self.identify_running
            or self.instant_destroy_running
            or self.salvage_running
            or self.storage_scan_running
            or self.auto_cleanup_running
            or self.manual_vendor_running
        ):
            return

        current_signature = self._get_inventory_signature()
        settings = _normalize_identify_settings(self.identify_settings)
        if not bool(settings.on_inventory_change):
            self.identify_rescan_requested = False
            self.identify_last_signature = current_signature
            return
        if not self._has_enabled_identify_settings():
            self.identify_rescan_requested = False
            self.identify_last_signature = current_signature
            return

        should_rescan = bool(self.identify_rescan_requested)
        if not should_rescan:
            if current_signature == self.identify_last_signature:
                return
            if not self.identify_poll_timer.IsExpired():
                return

        self.identify_rescan_requested = False
        self.identify_poll_timer.Reset()
        self._queue_identify_now(auto_triggered=True)

    def _request_salvage_rescan(self):
        self.salvage_rescan_requested = True

    def _format_salvage_summary(
        self,
        outcome: ExecutionPhaseOutcome,
        blocked_counts: dict[str, int],
        *,
        auto_triggered: bool = False,
    ) -> str:
        subject = "Auto Salvage" if auto_triggered else "Salvage"
        parts: list[str] = []
        if outcome.completed > 0:
            parts.append(f"{subject} processed {outcome.completed} item(s).")
        elif outcome.attempted > 0:
            parts.append(f"{subject} found matching items, but none were confirmed salvaged.")
        else:
            parts.append(f"{subject} found no eligible items.")
        if outcome.timeout_failures > 0:
            parts.append(f"{outcome.timeout_failures} timeout/failure(s).")
        if outcome.unavailable > 0:
            parts.append(f"Skipped {outcome.unavailable} unavailable/blocked item(s).")
        if outcome.depleted > 0:
            parts.append(f"{outcome.depleted} item(s) were already gone.")
        for reason, count in sorted(blocked_counts.items()):
            if count > 0:
                parts.append(f"Skipped {count} {reason}.")
        return " ".join(parts)

    def _queue_salvage_now(self, *, auto_triggered: bool = False):
        if self.salvage_running:
            return
        self.salvage_running = True
        GLOBAL_CACHE.Coroutines.append(self._run_salvage_pass(auto_triggered=auto_triggered, running_already_marked=True))

    def _get_salvage_session_value(self, session: object, key: str, default: object = None) -> object:
        if isinstance(session, dict):
            return session.get(key, default)
        return getattr(session, key, default)

    def _salvage_session_is_active(self, session: object) -> bool:
        return bool(self._get_salvage_session_value(session, "active", False))

    def _get_salvage_session_item_id(self, session: object) -> int:
        return max(0, _safe_int(self._get_salvage_session_value(session, "item_id", 0), 0))

    def _get_salvage_session_chosen_option(self, session: object) -> str:
        raw_option = str(self._get_salvage_session_value(session, "chosen_option", "") or "").strip()
        return _normalize_salvage_option(raw_option) if raw_option else ""

    def _get_salvage_session_available_option_names(self, session: object) -> list[str]:
        available_names = self._get_salvage_session_value(session, "available_option_names", [])
        if isinstance(available_names, (list, tuple, set)):
            return [
                option
                for option in (
                    _normalize_salvage_option(str(value or "").strip())
                    for value in available_names
                )
                if option in SALVAGE_SESSION_OPTIONS
            ]

        available_options = self._get_salvage_session_value(session, "available_options", {})
        if isinstance(available_options, dict):
            return [
                option
                for option in (SALVAGE_OPTION_MATERIALS, SALVAGE_OPTION_PREFIX, SALVAGE_OPTION_SUFFIX, SALVAGE_OPTION_INSCRIPTION)
                if bool(available_options.get(option, False))
            ]
        return []

    def _format_salvage_session_option_names(self, session: object) -> str:
        option_names = self._get_salvage_session_available_option_names(session)
        return ", ".join(option_names) if option_names else "none"

    def _log_salvage_session_read(self, item_id: int, session: object):
        session_item_id = self._get_salvage_session_item_id(session)
        chosen_option = self._get_salvage_session_chosen_option(session) or "none"
        self._salvage_flow_log(
            f"MR Salvage session read for item {int(item_id)}: "
            f"session_item={session_item_id or 'none'} available=[{self._format_salvage_session_option_names(session)}] "
            f"chosen={chosen_option}."
        )

    def _salvage_session_option_available(self, session: object, option: str) -> bool:
        safe_option = _resolve_salvage_session_option(option)
        available_options = self._get_salvage_session_value(session, "available_options", {})
        if isinstance(available_options, dict) and bool(available_options.get(safe_option, False)):
            return True
        available_names = self._get_salvage_session_value(session, "available_option_names", [])
        if isinstance(available_names, (list, tuple, set)):
            return safe_option in {str(value or "").strip().lower() for value in available_names}
        return False

    def _get_salvage_session_option_item_id(self, session: object, option: str) -> int:
        safe_option = _resolve_salvage_session_option(option)
        option_item_ids = self._get_salvage_session_value(session, "option_item_ids", {})
        if isinstance(option_item_ids, dict):
            return max(0, _safe_int(option_item_ids.get(safe_option, 0), 0))
        return 0

    def _wait_for_salvage_session_for_item(
        self,
        inventory_instance: object,
        item_id: int,
        *,
        timeout_ms: int = 1500,
        poll_ms: int = 50,
    ):
        waited_ms = 0
        last_session: object = {}
        while waited_ms <= max(0, int(timeout_ms)):
            try:
                last_session = inventory_instance.GetSalvageSessionInfo()
            except Exception:
                last_session = {}
            if self._salvage_session_is_active(last_session):
                if self._get_salvage_session_item_id(last_session) == int(item_id):
                    return last_session
            yield from Routines.Yield.wait(max(1, int(poll_ms)))
            waited_ms += max(1, int(poll_ms))
        return last_session

    def _get_salvage_runtime_state(self, inventory_instance: object) -> tuple[bool, bool]:
        try:
            is_salvaging = bool(inventory_instance.IsSalvaging())
        except Exception:
            is_salvaging = False
        try:
            transaction_done = bool(inventory_instance.IsSalvageTransactionDone())
        except Exception:
            transaction_done = False
        return is_salvaging, transaction_done

    def _has_native_salvage_session_api(self, inventory_instance: object) -> bool:
        return (
            callable(getattr(inventory_instance, "StartSalvage", None))
            and callable(getattr(inventory_instance, "GetSalvageSessionInfo", None))
            and callable(getattr(inventory_instance, "SelectSalvageSessionOption", None))
        )

    def _get_exact_upgrade_salvage_bridge(self) -> _MerchantRulesExactUpgradeSalvageBridge:
        bridge = getattr(self, "_exact_upgrade_salvage_bridge", None)
        if bridge is None:
            bridge = _MerchantRulesExactUpgradeSalvageBridge(self._get_inventory_item_ids, owner=self)
            self._exact_upgrade_salvage_bridge = bridge
        return bridge

    def _get_salvage_upgrade_session_support_status(self) -> tuple[bool, str]:
        cached_value = getattr(self, "_salvage_upgrade_session_support_cache", None)
        if isinstance(cached_value, bool):
            cached_reason = str(getattr(self, "_salvage_upgrade_session_support_reason", "") or "").strip()
            return cached_value, cached_reason

        try:
            supported, reason = self._get_exact_upgrade_salvage_bridge().is_available()
        except Exception as exc:
            supported = False
            reason = f"{SALVAGE_UPGRADE_BACKEND_UNAVAILABLE_REASON}: check failed: {exc}"

        self._salvage_upgrade_session_support_cache = bool(supported)
        self._salvage_upgrade_session_support_reason = str(reason or "").strip()
        return bool(supported), self._salvage_upgrade_session_support_reason

    def _has_salvage_upgrade_session_support(self) -> bool:
        supported, _reason = self._get_salvage_upgrade_session_support_status()
        return bool(supported)

    def _any_salvage_related_window_open(self) -> bool:
        try:
            from Sources.frenkeyLib.ItemHandling.UIManagerExtensions import UIManagerExtensions

            return bool(UIManagerExtensions.AnySalvageRelatedWindowOpen())
        except Exception:
            return False

    def _queue_salvage_start(self, item_id: int, salvage_kit_id: int, attempt: int):
        from Py4GWCoreLib.Inventory import Inventory

        self._salvage_flow_log(
            f"MR Salvage issuing start attempt {int(attempt)} for item {int(item_id)} "
            f"with kit {int(salvage_kit_id)} ({self._get_salvage_kit_label(int(salvage_kit_id))})."
        )
        ActionQueueManager().AddAction("SALVAGE", Inventory.SalvageItem, int(item_id), int(salvage_kit_id))
        queue_drained = yield from self._wait_for_action_queue_empty("SALVAGE", timeout_ms=5000, step_ms=50)
        if not queue_drained:
            ConsoleLog(MODULE_NAME, f"MR Salvage timed out starting item {int(item_id)}.", Console.MessageType.Warning)
            return False
        yield from Routines.Yield.wait(150)
        return True

    def _direct_salvage_start(self, inventory_instance: object, item_id: int, salvage_kit_id: int, attempt: int):
        start_method = getattr(inventory_instance, "StartSalvage", None)
        start_method_name = "StartSalvage" if callable(start_method) else "Salvage"
        self._salvage_flow_log(
            f"MR Salvage issuing direct start attempt {int(attempt)} for item {int(item_id)} "
            f"with kit {int(salvage_kit_id)} ({self._get_salvage_kit_label(int(salvage_kit_id))}) "
            f"via PyInventory.{start_method_name}."
        )
        try:
            if callable(start_method):
                start_result = start_method(int(salvage_kit_id), int(item_id))
            else:
                start_result = inventory_instance.Salvage(int(salvage_kit_id), int(item_id))
        except Exception as exc:
            ConsoleLog(
                MODULE_NAME,
                f"MR Salvage direct start failed for item {int(item_id)} with kit {int(salvage_kit_id)}: {exc}.",
                Console.MessageType.Warning,
            )
            return False
        self._salvage_flow_log(
            f"MR Salvage native start result for item {int(item_id)} via PyInventory.{start_method_name}: {start_result}."
        )
        if start_result is False:
            ConsoleLog(
                MODULE_NAME,
                f"MR Salvage native start rejected item {int(item_id)} with kit {int(salvage_kit_id)}.",
                Console.MessageType.Warning,
            )
            return False
        yield from Routines.Yield.wait(150)
        return True

    def _start_salvage_and_wait_for_session(
        self,
        inventory_instance: object,
        item_id: int,
        salvage_kit_id: int,
        *,
        max_attempts: int = 2,
        session_timeout_ms: int = 3500,
    ):
        last_session: object = {}
        attempts = max(1, int(max_attempts))
        for attempt in range(1, attempts + 1):
            started = yield from self._direct_salvage_start(inventory_instance, item_id, salvage_kit_id, attempt)
            if not started:
                return {}, attempt, "start_failed"

            last_session = yield from self._wait_for_salvage_session_for_item(
                inventory_instance,
                item_id,
                timeout_ms=max(0, int(session_timeout_ms)),
                poll_ms=50,
            )
            self._log_salvage_session_read(item_id, last_session)
            if self._salvage_session_is_active(last_session):
                return last_session, attempt, "active"

            is_salvaging, transaction_done = self._get_salvage_runtime_state(inventory_instance)
            self._salvage_flow_log(
                f"MR Salvage start attempt {attempt} for item {int(item_id)} produced no active session; "
                f"is_salvaging={is_salvaging} transaction_done={transaction_done}."
            )

            if attempt >= attempts:
                break
            if self._any_salvage_related_window_open():
                return last_session, attempt, "window_without_session"
            live_item = self._build_inventory_item_info(int(item_id))
            if live_item is None or not bool(live_item.salvageable):
                return last_session, attempt, "item_changed"

            self._salvage_flow_log(
                f"MR Salvage retrying start for item {int(item_id)} after no active session appeared."
            )

        return last_session, attempts, "no_session"

    def _select_salvage_session_option(
        self,
        inventory_instance: object,
        item_id: int,
        option: str,
    ):
        safe_option = _resolve_salvage_session_option(option)
        try:
            session = inventory_instance.GetSalvageSessionInfo()
        except Exception as exc:
            return False, f"salvage option unavailable: failed reading salvage session ({exc}).", 0

        if not self._salvage_session_is_active(session):
            return False, "salvage option unavailable: no active salvage session.", 0
        session_item_id = self._get_salvage_session_item_id(session)
        if session_item_id != int(item_id):
            return False, f"salvage popup mismatch: active item {session_item_id}, expected {int(item_id)}.", 0
        if not self._salvage_session_option_available(session, safe_option):
            return False, f"salvage option unavailable: {_get_salvage_option_label(safe_option)} is not available.", 0

        option_item_id = self._get_salvage_session_option_item_id(session, safe_option)
        chosen_option = self._get_salvage_session_chosen_option(session)
        if chosen_option == safe_option:
            self._salvage_flow_log(
                f"MR Salvage option already selected for item {int(item_id)}: requested={safe_option} chosen={chosen_option}."
            )
            return True, "", option_item_id

        try:
            selected = bool(inventory_instance.SelectSalvageSessionOption(safe_option))
        except Exception as exc:
            self._salvage_flow_log(
                f"MR Salvage SelectSalvageSessionOption('{safe_option}') -> error.",
                Console.MessageType.Warning,
            )
            return False, f"salvage option unavailable: SelectSalvageSessionOption failed ({exc}).", option_item_id
        self._salvage_flow_log(
            f"MR Salvage SelectSalvageSessionOption('{safe_option}') -> {selected}."
        )
        if not selected:
            return False, f"salvage option unavailable: native selection returned false for {_get_salvage_option_label(safe_option)}.", option_item_id

        waited_ms = 0
        while waited_ms <= 750:
            try:
                next_session = inventory_instance.GetSalvageSessionInfo()
            except Exception:
                next_session = {}
            if (
                self._salvage_session_is_active(next_session)
                and self._get_salvage_session_item_id(next_session) == int(item_id)
                and self._get_salvage_session_chosen_option(next_session) == safe_option
            ):
                return True, "", self._get_salvage_session_option_item_id(next_session, safe_option) or option_item_id
            yield from Routines.Yield.wait(50)
            waited_ms += 50
        return False, f"salvage option unavailable: {_get_salvage_option_label(safe_option)} did not become selected.", option_item_id

    def _confirm_salvage_choice_dialog(
        self,
        item_id: int,
        *,
        auto_confirm_materials_warning: bool = False,
    ):
        from Py4GWCoreLib.Inventory import Inventory
        from Py4GWCoreLib.UIManager import UIManager

        confirm_frame_id = Inventory._get_salvage_choice_confirm_frame_id()
        if confirm_frame_id == 0:
            return "confirm_missing"

        ActionQueueManager().AddAction("SALVAGE", UIManager.FrameClick, confirm_frame_id)
        queue_drained = yield from self._wait_for_action_queue_empty("SALVAGE", timeout_ms=5000, step_ms=50)
        if not queue_drained:
            return "queue_timeout"

        return (yield from Inventory._wait_for_salvage_choice_dialog_close(
            auto_confirm_materials_warning=auto_confirm_materials_warning,
            queue_name="SALVAGE",
            log_module=MODULE_NAME,
            queue_wait_timeout_ms=5000,
            poll_ms=50,
            close_timeout_ms=1500,
            debug_enabled=bool(self.debug_logging),
            item_id=int(item_id),
            after_action_label="confirm click",
        ))

    def _cancel_active_salvage_choice_dialog(self) -> bool:
        try:
            from Sources.frenkeyLib.ItemHandling.UIManagerExtensions import UIManagerExtensions

            return bool(UIManagerExtensions.CancelSalvageOption())
        except Exception:
            return False

    def _get_materials_confirm_yes_frame_id(self) -> int:
        try:
            from Py4GWCoreLib.Inventory import Inventory

            yes_frame_id = int(Inventory._get_salvage_choice_material_confirm_yes_frame_id() or 0)
            if yes_frame_id > 0:
                return yes_frame_id
        except Exception:
            pass

        try:
            from Py4GWCoreLib.UIManager import UIManager
        except Exception:
            return 0

        candidate_frame_ids = [
            UIManager.GetChildFrameID(140452905, [6, 98, 6]),
            UIManager.GetChildFrameID(140452905, [6, 100, 6]),
            UIManager.GetChildFrameID(140452905, [6, 110, 6]),
            UIManager.GetChildFrameID(140452905, [6, 111, 6]),
            UIManager.GetChildFrameID(684387150, [0, 6]),
        ]
        for frame_id in candidate_frame_ids:
            try:
                safe_frame_id = int(frame_id or 0)
            except Exception:
                safe_frame_id = 0
            if safe_frame_id > 0 and UIManager.FrameExists(safe_frame_id):
                return safe_frame_id
        return 0

    def _wait_and_confirm_materials_popup(self, item_id: int, kit_id: int, *, timeout_ms: int = 2000):
        from Py4GWCoreLib.UIManager import UIManager

        waited_ms = 0
        yield from Routines.Yield.wait(100)
        while waited_ms <= max(0, int(timeout_ms)):
            yes_frame_id = self._get_materials_confirm_yes_frame_id()
            if yes_frame_id > 0:
                self._salvage_flow_log(
                    f"MR Salvage materials confirmation visible for item {int(item_id)} "
                    f"with {self._get_salvage_kit_label(int(kit_id))}; accepting materials confirmation."
                )
                ActionQueueManager().AddAction("SALVAGE", UIManager.FrameClick, yes_frame_id)
                ActionQueueManager().AddAction("SALVAGE", UIManager.TestMouseClickAction, yes_frame_id, 0, 0)
                queue_drained = yield from self._wait_for_action_queue_empty("SALVAGE", timeout_ms=5000, step_ms=50)
                if not queue_drained:
                    return "queue_timeout"
                yield from Routines.Yield.wait(150)
                return "handled"
            yield from Routines.Yield.wait(50)
            waited_ms += 50
        return "not_visible"

    def _has_salvage_upgrade_removed(self, item_id: int, option: str) -> bool:
        if int(item_id) not in set(self._get_inventory_item_ids()):
            return True
        safe_option = _resolve_salvage_session_option(option)
        getter_name_by_option = {
            SALVAGE_OPTION_PREFIX: "GetPrefixUpgrade",
            SALVAGE_OPTION_SUFFIX: "GetSuffixUpgrade",
            SALVAGE_OPTION_INSCRIPTION: "GetInscriptionUpgrade",
        }
        getter_name = getter_name_by_option.get(safe_option, "")
        if not getter_name:
            return False
        try:
            from Py4GWCoreLib.Item import Item

            getter = getattr(Item.Customization, getter_name, None)
            if not callable(getter):
                return False
            return getter(int(item_id)) is None
        except Exception:
            return False

    def _salvage_one_item_with_rule(
        self,
        candidate: SalvageCandidate,
        enabled_sell_rules: list[tuple[int, SellRule]],
        *,
        auto_triggered: bool = False,
    ):
        mode = "auto" if auto_triggered else "manual"
        item = candidate.item
        rule = _normalize_salvage_rule(candidate.rule) or SalvageRule()
        live_item = self._build_inventory_item_info(int(item.item_id))
        if live_item is None:
            return "missing_item"

        live_item_label = self._format_inventory_item_log_label(live_item)
        preflight_block_reason = self._get_salvage_candidate_block_reason(
            live_item,
            enabled_sell_rules,
            salvage_rule=rule,
            require_salvage_kit=False,
            mode=mode,
        )
        if preflight_block_reason:
            self._debug_log(
                f"MR Salvage recheck skipped {live_item_label} ({live_item.item_id}): {preflight_block_reason}"
            )
            return "blocked"

        configured_option = _normalize_salvage_option(rule.salvage_option)
        selected_option = _resolve_salvage_session_option(configured_option)
        auto_slot_resolution = SalvageUpgradeSlotResolution()
        if _is_auto_exact_upgrade_salvage_option(configured_option):
            auto_slot_resolution = self._get_auto_salvage_upgrade_slot_resolution(rule, live_item)
            if auto_slot_resolution.selected_option:
                selected_option = auto_slot_resolution.selected_option
        salvage_kit_id = self._get_salvage_kit_id_for_option(selected_option)
        block_reason = self._get_salvage_candidate_block_reason(
            live_item,
            enabled_sell_rules,
            salvage_rule=rule,
            require_salvage_kit=True,
            salvage_kit_id=salvage_kit_id,
            mode=mode,
        )
        if block_reason:
            self._debug_log(f"MR Salvage recheck skipped {live_item_label} ({live_item.item_id}): {block_reason}")
            return "blocked"

        item_id = int(live_item.item_id)
        starting_quantity = max(1, int(live_item.quantity))
        rarity_key = _normalize_rarity_key(str(live_item.rarity or ""))
        selection_reason = candidate.reason or self._get_salvage_rule_filter_reason(rule, live_item)
        option_label = _get_salvage_option_label(configured_option)
        if _is_auto_exact_upgrade_salvage_option(configured_option):
            if selected_option not in SALVAGE_UPGRADE_OPTIONS:
                self._debug_log(
                    f"MR Salvage recheck skipped {live_item_label} ({live_item.item_id}): "
                    "specific upgrade salvage did not resolve to an upgrade slot"
                )
                return "blocked"
            inferred_label = _get_salvage_option_label(selected_option)
            matched_label_text = self._format_compact_list(auto_slot_resolution.matched_labels, limit=3)
            option_label = f"{option_label} -> {inferred_label}"
            if matched_label_text:
                selection_reason = f"{selection_reason}; inferred {inferred_label} from {matched_label_text}"
        self._debug_log(
            f"MR Salvage starting {live_item_label} ({item_id}) using kit {int(salvage_kit_id)}; "
            f"{selection_reason}; {option_label}."
        )
        rule_reference = self._format_salvage_rule_reference(int(candidate.rule_index), rule) if int(candidate.rule_index) >= 0 else "Salvage Rule"
        self._salvage_flow_log(
            f"MR Salvage matched {live_item_label} ({item_id}) with {rule_reference}: "
            f"requested={option_label}; kit={int(salvage_kit_id)} ({self._get_salvage_kit_label(int(salvage_kit_id))})."
        )

        option_item_id = 0
        if selected_option in SALVAGE_UPGRADE_OPTIONS:
            bridge_result = yield from self._get_exact_upgrade_salvage_bridge().salvage_exact_upgrade(
                item_id,
                selected_option,
                preferred_kit_id=int(salvage_kit_id),
                timeout_ms=5000,
                debug_enabled=bool(self.debug_logging),
            )
            bridge_status = str(getattr(bridge_result, "status", "") or "failed")
            bridge_reason = str(getattr(bridge_result, "reason", "") or "").strip()
            if not bool(getattr(bridge_result, "success", False)):
                ConsoleLog(
                    MODULE_NAME,
                    f"MR Salvage skipped {live_item_label} ({item_id}): "
                    f"{bridge_reason or 'exact-upgrade salvage backend failed'}.",
                    Console.MessageType.Warning,
                )
                return bridge_status if bridge_status in {"blocked", "failed"} else "failed"
            self._salvage_flow_log(
                f"MR Salvage verified {_get_salvage_option_label(selected_option)} removal for item {item_id}."
            )
            return bridge_status if bridge_status in {"processed", "salvaged"} else "processed"

        else:
            started = yield from self._queue_salvage_start(item_id, int(salvage_kit_id), 1)
            if not started:
                return "failed"
            if rarity_key in {"purple", "gold"}:
                materials_confirm_status = yield from self._wait_and_confirm_materials_popup(
                    item_id,
                    int(salvage_kit_id),
                    timeout_ms=2500,
                )
                if materials_confirm_status != "handled":
                    ConsoleLog(MODULE_NAME, f"MR Salvage did not find the materials confirmation for item {item_id}.", Console.MessageType.Warning)
                    return "failed"
            else:
                materials_confirm_status = yield from self._wait_and_confirm_materials_popup(
                    item_id,
                    int(salvage_kit_id),
                    timeout_ms=700,
                )
                if materials_confirm_status not in {"handled", "not_visible"}:
                    ConsoleLog(
                        MODULE_NAME,
                        f"MR Salvage could not accept materials confirmation for item {item_id}: {materials_confirm_status}.",
                        Console.MessageType.Warning,
                    )
                    return "failed"

        waited_ms = 0
        while waited_ms <= 10000:
            yield from Routines.Yield.wait(50)
            waited_ms += 50
            if item_id not in set(self._get_inventory_item_ids()):
                self._debug_log(f"MR Salvage completed {live_item_label} ({item_id}); item left inventory.")
                return "salvaged"
            try:
                current_quantity = max(0, int(GLOBAL_CACHE.Item.Properties.GetQuantity(item_id)))
            except Exception:
                current_quantity = starting_quantity
            if current_quantity < starting_quantity:
                self._debug_log(f"MR Salvage completed {live_item_label} ({item_id}); quantity dropped.")
                return "salvaged"
            current_item = self._build_inventory_item_info(item_id)
            if current_item is not None and not bool(current_item.salvageable):
                self._debug_log(f"MR Salvage processed {live_item_label} ({item_id}); item is no longer salvageable.")
                return "processed"
            if selected_option in SALVAGE_UPGRADE_OPTIONS and self._has_salvage_upgrade_removed(item_id, selected_option):
                option_suffix = f" option_item_id={option_item_id}" if option_item_id > 0 else ""
                self._debug_log(
                    f"MR Salvage processed {live_item_label} ({item_id}); "
                    f"{_get_salvage_option_label(selected_option)} removed.{option_suffix}"
                )
                return "processed"

        ConsoleLog(MODULE_NAME, f"MR Salvage timed out waiting for result on item {item_id}.", Console.MessageType.Warning)
        return "failed"

    def _run_salvage_pass(self, *, auto_triggered: bool = False, running_already_marked: bool = False):
        if self.salvage_running and not running_already_marked:
            return
        self.salvage_running = True
        self.last_error = ""
        self.last_salvage_summary = ""
        paused_inventory_plus = None
        try:
            mode = "auto" if auto_triggered else "manual"
            if auto_triggered and not bool(_normalize_salvage_settings(self.salvage_settings).on_inventory_change):
                return
            if not self._has_enabled_salvage_settings():
                self.last_salvage_summary = (
                    "Auto Salvage is enabled, but no salvage rules are active."
                    if auto_triggered
                    else "Salvage has no active rules."
                )
                self.status_message = self.last_salvage_summary
                return

            items = self._collect_inventory_items()
            self.salvage_last_signature = self._get_inventory_signature(items)
            enabled_sell_rules = self._collect_enabled_sell_rules()
            candidates, blocked_counts = self._collect_salvage_candidates(
                items,
                enabled_sell_rules,
                require_salvage_kit=True,
                mode=mode,
            )
            if not candidates:
                self.last_salvage_summary = self._format_salvage_summary(
                    ExecutionPhaseOutcome(label="MR Salvage", measure_label="items"),
                    blocked_counts,
                    auto_triggered=auto_triggered,
                )
                self.status_message = self.last_salvage_summary
                self._debug_log(self.last_salvage_summary)
                return

            paused_inventory_plus = self._pause_inventory_plus()
            if paused_inventory_plus is not None:
                self._debug_log("MR Salvage: paused Inventory Plus.")

            outcome = ExecutionPhaseOutcome(label="MR Salvage", measure_label="items", attempted=len(candidates))
            for candidate in candidates:
                status = yield from self._salvage_one_item_with_rule(
                    candidate,
                    enabled_sell_rules,
                    auto_triggered=auto_triggered,
                )
                if status in {"salvaged", "processed"}:
                    outcome.completed += 1
                    continue
                if status == "missing_item":
                    outcome.depleted += 1
                    continue
                if status == "blocked":
                    outcome.unavailable += 1
                    continue
                outcome.timeout_failures += 1

            self.last_salvage_summary = self._format_salvage_summary(
                outcome,
                blocked_counts,
                auto_triggered=auto_triggered,
            )
            self.status_message = self.last_salvage_summary
            ConsoleLog(MODULE_NAME, self.last_salvage_summary, Console.MessageType.Info)
            if outcome.completed > 0:
                self._mark_preview_dirty("Inventory changed due to MR Salvage. Preview again before execution.")
        except Exception as exc:
            self.last_error = f"{exc}"
            self.last_salvage_summary = "MR Salvage failed. See the console log for details."
            self.status_message = self.last_salvage_summary
            ConsoleLog(MODULE_NAME, f"MR Salvage error: {exc}", Console.MessageType.Error)
            ConsoleLog(MODULE_NAME, traceback.format_exc(), Console.MessageType.Error)
        finally:
            if paused_inventory_plus is not None:
                paused_inventory_plus.resume()
                self._debug_log("MR Salvage: resumed Inventory Plus.")
            self.salvage_running = False
            self.salvage_rescan_requested = False
            self.salvage_poll_timer.Reset()
            self.salvage_last_signature = self._get_inventory_signature()
            yield

    def _update_salvage_runtime(self):
        if not Map.IsMapReady():
            return
        if (
            self.execution_running
            or self.travel_preview_running
            or self.identify_running
            or self.instant_destroy_running
            or self.salvage_running
            or self.storage_scan_running
            or self.auto_cleanup_running
            or self.manual_vendor_running
        ):
            return

        current_signature = self._get_inventory_signature()
        if not bool(_normalize_salvage_settings(self.salvage_settings).on_inventory_change):
            self.salvage_rescan_requested = False
            self.salvage_last_signature = current_signature
            return
        if not self._has_enabled_salvage_settings():
            self.salvage_rescan_requested = False
            self.salvage_last_signature = current_signature
            return

        should_rescan = bool(self.salvage_rescan_requested)
        if not should_rescan:
            if current_signature == self.salvage_last_signature:
                return
            if not self.salvage_poll_timer.IsExpired():
                return

        self.salvage_rescan_requested = False
        self.salvage_poll_timer.Reset()
        self._queue_salvage_now(auto_triggered=True)

    def _is_destroy_auto_enabled(self) -> bool:
        return bool(self.destroy_instant_enabled or self.destroy_auto_enabled)

    def _request_instant_destroy_rescan(self):
        self.instant_destroy_rescan_requested = True

    def _run_destroy_pass(
        self,
        *,
        require_auto_enabled: bool,
        summary_subject: str,
        dirty_reason: str,
    ):
        if self.instant_destroy_running:
            return
        if require_auto_enabled and not self._is_destroy_auto_enabled():
            return

        self.instant_destroy_running = True
        paused_inventory_plus = None
        subject = str(summary_subject or "Auto Destroy").strip() or "Auto Destroy"
        try:
            enabled_destroy_rules = self._collect_enabled_destroy_rules()
            items = self._collect_inventory_items()
            self.instant_destroy_last_signature = self._get_inventory_signature(items)
            if not enabled_destroy_rules:
                self.last_instant_destroy_summary = f"{subject}: no destroy rules are active."
                return

            instant_plan = PlanResult(supported_map=True, coords={MERCHANT_TYPE_INVENTORY: None})
            self._plan_destroy_actions(
                instant_plan,
                items,
                enabled_destroy_rules,
                self._collect_enabled_sell_rules(),
                set(),
            )
            blocked_destroy_entries = [
                entry
                for entry in instant_plan.entries
                if entry.action_type == "destroy"
                and entry.merchant_type == MERCHANT_TYPE_INVENTORY
                and entry.state == PLAN_STATE_SKIPPED
                and str(entry.reason).startswith("Blocked by ")
            ]
            protected_skip_count = sum(
                1
                for entry in blocked_destroy_entries
                if _is_protected_destroy_skip_entry(entry)
            )
            blocked_destroy_count = len(blocked_destroy_entries)
            split_block_count = sum(
                1
                for entry in blocked_destroy_entries
                if "Keep count requires splitting" in str(entry.reason)
            )
            destroy_actions = list({
                int(action.item_id): action
                for action in instant_plan.destroy_actions
                if int(action.item_id) > 0
            }.values())
            if not destroy_actions and instant_plan.destroy_item_ids:
                destroy_actions = [
                    int(item_id)
                    for item_id in dict.fromkeys(instant_plan.destroy_item_ids)
                    if int(item_id) > 0
                ]
            if not destroy_actions:
                if protected_skip_count > 0:
                    self.last_instant_destroy_summary = f"{subject} skipped {protected_skip_count} protected item(s)."
                elif split_block_count > 0:
                    self.last_instant_destroy_summary = (
                        f"{subject} found matching items, but a required stack split could not be performed safely."
                    )
                elif blocked_destroy_count > 0:
                    self.last_instant_destroy_summary = (
                        f"{subject} found matching items, but all matching items were blocked by safety checks."
                    )
                else:
                    self.last_instant_destroy_summary = f"{subject} found no matching items."
                return

            paused_inventory_plus = self._pause_inventory_plus()
            destroy_outcome = yield from self._execute_destroy_phase(destroy_actions)
            if destroy_outcome.completed > 0:
                self._mark_preview_dirty(dirty_reason)

            summary_parts: list[str] = []
            if destroy_outcome.completed > 0:
                summary_parts.append(f"{subject} removed {destroy_outcome.completed} item(s).")
            else:
                summary_parts.append(f"{subject} found matching items, but none were confirmed destroyed.")
            if protected_skip_count > 0:
                summary_parts.append(f"Skipped {protected_skip_count} protected item(s).")
            if destroy_outcome.timeout_failures > 0:
                summary_parts.append(f"{destroy_outcome.timeout_failures} destroy confirmation timeout(s).")
            if destroy_outcome.depleted > 0:
                summary_parts.append(f"{destroy_outcome.depleted} item(s) were already gone.")
            self.last_instant_destroy_summary = " ".join(summary_parts)
        finally:
            if paused_inventory_plus is not None:
                paused_inventory_plus.resume()
            self.instant_destroy_running = False
            self.instant_destroy_rescan_requested = False
            self.instant_destroy_poll_timer.Reset()
            self.instant_destroy_last_signature = self._get_inventory_signature()
            yield

    def _run_instant_destroy_pass(self):
        yield from self._run_destroy_pass(
            require_auto_enabled=True,
            summary_subject="Auto Destroy",
            dirty_reason="Inventory changed due to Auto Destroy. Preview again before execution.",
        )

    def _queue_destroy_now(self):
        GLOBAL_CACHE.Coroutines.append(
            self._run_destroy_pass(
                require_auto_enabled=False,
                summary_subject="Run Destroy Now",
                dirty_reason="Inventory changed due to Run Destroy Now. Preview again before execution.",
            )
        )

    def _update_instant_destroy_runtime(self):
        if not Map.IsMapReady():
            return
        if (
            self.execution_running
            or self.travel_preview_running
            or self.identify_running
            or self.instant_destroy_running
            or self.salvage_running
            or self.storage_scan_running
            or self.auto_cleanup_running
            or self.manual_vendor_running
        ):
            return

        current_signature = self._get_inventory_signature()
        if not self._is_destroy_auto_enabled():
            self.instant_destroy_rescan_requested = False
            self.instant_destroy_last_signature = current_signature
            return

        should_rescan = bool(self.instant_destroy_rescan_requested)
        if not should_rescan:
            if current_signature == self.instant_destroy_last_signature:
                return
            if not self.instant_destroy_poll_timer.IsExpired():
                return

        self.instant_destroy_rescan_requested = False
        self.instant_destroy_poll_timer.Reset()
        GLOBAL_CACHE.Coroutines.append(self._run_instant_destroy_pass())

