    def _apply_identify_rarity_preset(self, settings: IdentifySettings, enabled_keys: set[str]) -> bool:
        next_flags = {
            key: key in enabled_keys
            for key, _label in RARITY_OPTION_ORDER
        }
        if _normalize_identify_rarity_flags(settings.rarities) == next_flags:
            return False
        settings.rarities = next_flags
        return True

    def _format_identify_filter_summary(self, settings: IdentifySettings) -> str:
        normalized_settings = _normalize_identify_settings(settings)
        rarity_labels = [
            label
            for key, label in RARITY_OPTION_ORDER
            if bool(normalized_settings.rarities.get(key, False))
        ]
        modes: list[str] = []
        if normalized_settings.before_execute:
            modes.append("before Execute")
        if normalized_settings.on_inventory_change:
            modes.append("on inventory change")
        mode_text = ", ".join(modes) if modes else "manual run only"
        rarity_text = ", ".join(rarity_labels) if rarity_labels else "no rarities selected"
        return f"Selected: {rarity_text} | Runs: {mode_text}"

    def _draw_identify_status_badges(self, settings: IdentifySettings) -> int:
        normalized_settings = _normalize_identify_settings(settings)
        selector_count = sum(1 for value in normalized_settings.rarities.values() if bool(value))
        auto_enabled = bool(normalized_settings.before_execute or normalized_settings.on_inventory_change)
        ready = selector_count > 0

        self._draw_subsection_label("Identify:")
        PyImGui.same_line(0, 8)
        self._draw_inline_badge("On" if auto_enabled else "Off", UI_COLOR_SUCCESS if auto_enabled else UI_COLOR_MUTED)
        PyImGui.same_line(0, 6)
        self._draw_inline_badge(
            f"Rarities: {selector_count}",
            UI_COLOR_SUCCESS if ready else (UI_COLOR_WARNING if auto_enabled else UI_COLOR_MUTED),
        )
        if normalized_settings.before_execute:
            PyImGui.same_line(0, 6)
            self._draw_inline_badge("Execute", UI_COLOR_SUCCESS if ready else UI_COLOR_WARNING)
        if normalized_settings.on_inventory_change:
            PyImGui.same_line(0, 6)
            self._draw_inline_badge("Pickup", UI_COLOR_SUCCESS if ready else UI_COLOR_WARNING)
        if not auto_enabled:
            PyImGui.same_line(0, 6)
            self._draw_inline_badge("Manual", UI_COLOR_MUTED)
        return selector_count

    def _draw_identify_workspace(self):
        settings = _normalize_identify_settings(self.identify_settings)
        changed = False

        self._draw_section_heading("Identify")
        self._draw_secondary_text(
            "Identify targets unidentified inventory items by exact rarity. Identify before Execute runs after any configured travel, then Merchant Rules rebuilds the live plan before the rest of Execute continues."
        )

        selector_count = self._draw_identify_status_badges(settings)
        self._draw_secondary_text(self._format_identify_filter_summary(settings), wrapped=False)
        if selector_count <= 0:
            self._draw_warning_text("Choose at least one rarity before Identify can find items.")

        PyImGui.separator()
        self._draw_section_heading("When to Identify")
        before_execute = PyImGui.checkbox(
            "Identify before Execute##merchant_rules_identify_before_execute",
            bool(settings.before_execute),
        )
        self._draw_helper_tooltip("identify_before_execute")
        if before_execute != settings.before_execute:
            settings.before_execute = before_execute
            changed = True

        on_inventory_change = PyImGui.checkbox(
            "Identify selected items on inventory change / pickup##merchant_rules_identify_on_inventory_change",
            bool(settings.on_inventory_change),
        )
        self._draw_helper_tooltip("identify_on_inventory_change")
        if on_inventory_change != settings.on_inventory_change:
            settings.on_inventory_change = on_inventory_change
            changed = True
            if settings.on_inventory_change:
                self._request_identify_rescan()
            else:
                self.identify_rescan_requested = False

        run_identify_reason = self._get_action_block_reason("identify")
        PyImGui.same_line(0, 8)
        PyImGui.begin_disabled(bool(run_identify_reason))
        run_identify_clicked = PyImGui.button("Run Identify Now##merchant_rules_run_identify_now")
        PyImGui.end_disabled()

        if run_identify_reason:
            self._draw_secondary_text(f"Run Identify Now: {run_identify_reason}")
        if selector_count > 0 and self._get_id_kit_id() <= 0:
            self._draw_warning_text("No ID kit found. Matching items will be claimed in Preview but cannot be identified yet.")
        if self.identify_running:
            PyImGui.text_colored("Identify is running.", UI_COLOR_INFO)
        if self.last_identify_summary:
            self._draw_secondary_text(self.last_identify_summary)
        if settings.on_inventory_change:
            self._draw_secondary_text("Identify pauses Inventory Plus while it runs.")

        PyImGui.separator()
        self._draw_section_heading("Rarities to Identify")
        changed = self._draw_identify_rarity_toggles(settings) or changed
        self._draw_helper_tooltip("identify_rarity_filters")
        self._draw_warning_text(
            "Selectors are exact. Blue identifies only blue items; it does not include purple, gold, or green.",
        )

        PyImGui.spacing()
        self._draw_section_heading("Quick Presets")
        presets: tuple[tuple[str, set[str]], ...] = (
            ("White", {"white"}),
            ("Blue", {"blue"}),
            ("Purple", {"purple"}),
            ("Gold", {"gold"}),
            ("Green", {"green"}),
            ("Blue/Purple/Gold", {"blue", "purple", "gold"}),
            ("All", {key for key, _label in RARITY_OPTION_ORDER}),
            ("None", set()),
        )
        for preset_index, (preset_label, enabled_keys) in enumerate(presets):
            if PyImGui.small_button(f"{preset_label}##merchant_rules_identify_preset_{preset_index}"):
                changed = self._apply_identify_rarity_preset(settings, enabled_keys) or changed
            if preset_index + 1 < len(presets):
                PyImGui.same_line(0, 6)

        if changed:
            self.identify_settings = _normalize_identify_settings(settings)
            self._save_profile()
            if self.identify_settings.on_inventory_change:
                self._request_identify_rescan()
            self._mark_preview_dirty("Identify settings changed. Preview again before execution.")

        if run_identify_clicked:
            self._queue_identify_now()

    def _draw_salvage_category_toggles(self, settings: SalvageRule | SalvageSettings, id_suffix: str = "") -> bool:
        changed = False
        self._draw_subsection_label("Categories")
        settings.categories = _normalize_salvage_category_flags(settings.categories)
        for category_index, (category_key, category_label) in enumerate(SALVAGE_CATEGORY_ORDER):
            current_value = bool(settings.categories.get(category_key, False))
            new_value = PyImGui.checkbox(f"##salvage_category_{id_suffix}_{category_key}", current_value)
            if new_value != current_value:
                settings.categories[category_key] = new_value
                changed = True
            PyImGui.same_line(0, 4)
            PyImGui.text(category_label)
            if category_index % 2 == 0 and category_index + 1 < len(SALVAGE_CATEGORY_ORDER):
                PyImGui.same_line(0, 12)
        return changed

    def _format_salvage_filter_summary(self, settings: SalvageSettings) -> str:
        normalized_settings = _normalize_salvage_settings(settings)
        enabled_rules = [
            rule
            for rule in normalized_settings.rules
            if bool(rule.enabled) and _salvage_rule_has_selectors(rule)
        ]
        if not enabled_rules:
            return "Current salvage filter: no rules selected"
        option_labels = [
            _get_salvage_option_label(rule.salvage_option)
            for rule in enabled_rules
        ]
        distinct_options = []
        for label in option_labels:
            if label not in distinct_options:
                distinct_options.append(label)
        return f"Current salvage filter: {len(enabled_rules)} active rule(s) | {', '.join(distinct_options)}"

    def _get_salvage_rule_summary(self, rule: SalvageRule) -> tuple[str, bool]:
        normalized_rule = _normalize_salvage_rule(rule) or SalvageRule()
        selector_parts: list[str] = []
        if normalized_rule.model_ids:
            selector_parts.append(f"{len(normalized_rule.model_ids)} exact model(s)")

        rarity_labels = [
            label
            for key, label in RARITY_OPTION_ORDER
            if bool(normalized_rule.rarities.get(key, False))
        ]
        if rarity_labels:
            selector_parts.append(f"Rarities: {', '.join(rarity_labels)}")

        category_labels = [
            label
            for key, label in SALVAGE_CATEGORY_ORDER
            if bool(normalized_rule.categories.get(key, False))
        ]
        if category_labels:
            selector_parts.append(f"Categories: {', '.join(category_labels)}")

        option_label = _get_salvage_option_label(normalized_rule.salvage_option)
        selected_option = _resolve_salvage_session_option(normalized_rule.salvage_option)
        is_auto_upgrade_option = _is_auto_exact_upgrade_salvage_option(normalized_rule.salvage_option)
        upgrade_target_count = _get_salvage_rule_upgrade_target_count(normalized_rule)
        if selected_option == SALVAGE_OPTION_MATERIALS and not is_auto_upgrade_option:
            selector_parts = []
            if normalized_rule.model_ids:
                selector_parts.append(f"{len(normalized_rule.model_ids)} exact model(s)")
            if rarity_labels:
                selector_parts.append(f"Rarities: {', '.join(rarity_labels)}")
            if category_labels:
                selector_parts.append(f"Categories: {', '.join(category_labels)}")
            if upgrade_target_count > 0:
                selector_parts.append("upgrade targets ignored")
            if not selector_parts:
                return "Materials | Choose at least one selector.", False
            return f"Materials | {' | '.join(selector_parts)}", True

        if is_auto_upgrade_option and upgrade_target_count <= 0:
            return f"{option_label} | Choose at least one specific upgrade target.", False
        if upgrade_target_count > 0:
            selector_parts.append(f"specific upgrades {upgrade_target_count}")
            if selected_option not in SALVAGE_UPGRADE_OPTIONS and not is_auto_upgrade_option:
                option_label = f"{option_label} (specific-upgrade targets require prefix/suffix/inscription)"
        if (
            (selected_option in SALVAGE_UPGRADE_OPTIONS or is_auto_upgrade_option)
            and not self._has_salvage_upgrade_session_support()
        ):
            option_label = f"{option_label} (extraction unavailable)"
        if not selector_parts:
            return f"{option_label} | Choose at least one selector.", False
        return f"{option_label} | {'; '.join(selector_parts)}", True

    def _draw_salvage_status_badges(self, settings: SalvageSettings) -> int:
        normalized_settings = _normalize_salvage_settings(settings)
        enabled_rule_count = sum(1 for rule in normalized_settings.rules if bool(rule.enabled))
        ready_rule_count = sum(
            1
            for rule in normalized_settings.rules
            if bool(rule.enabled) and _salvage_rule_has_selectors(rule)
        )
        auto_enabled = bool(normalized_settings.on_inventory_change)
        ready = ready_rule_count > 0

        self._draw_subsection_label("Salvage:")
        PyImGui.same_line(0, 8)
        self._draw_inline_badge("On" if auto_enabled else "Off", UI_COLOR_SUCCESS if auto_enabled else UI_COLOR_MUTED)
        PyImGui.same_line(0, 6)
        self._draw_inline_badge(
            f"Rules: {ready_rule_count}/{enabled_rule_count}",
            UI_COLOR_SUCCESS if ready else (UI_COLOR_WARNING if auto_enabled else UI_COLOR_MUTED),
        )
        if auto_enabled:
            PyImGui.same_line(0, 6)
            self._draw_inline_badge("Pickup", UI_COLOR_SUCCESS if ready else UI_COLOR_WARNING)
        else:
            PyImGui.same_line(0, 6)
            self._draw_inline_badge("Manual", UI_COLOR_MUTED)
        if any(bool(rule.categories.get(SALVAGE_CATEGORY_OTHER, False)) for rule in normalized_settings.rules):
            PyImGui.same_line(0, 6)
            self._draw_inline_badge("Other Items", UI_COLOR_WARNING)
        return ready_rule_count

    def _draw_salvage_option_combo(self, index: int, rule: SalvageRule) -> bool:
        current_option = _normalize_salvage_option(getattr(rule, "salvage_option", SALVAGE_OPTION_DEFAULT))
        preview_label = _get_salvage_option_dropdown_label(current_option)
        combo_flags = getattr(getattr(PyImGui, "ImGuiComboFlags", None), "NoFlag", 0)
        selectable_flags = getattr(getattr(PyImGui, "SelectableFlags", None), "NoFlag", 0)
        changed = False
        PyImGui.push_item_width(260)
        try:
            if PyImGui.begin_combo(
                f"Upgrade to salvage##merchant_rules_salvage_option_{index}",
                preview_label,
                combo_flags,
            ):
                try:
                    for option, label in SALVAGE_OPTION_DROPDOWN_ORDER:
                        selected = option == current_option
                        if PyImGui.selectable(
                            f"{label}##merchant_rules_salvage_option_{index}_{option}",
                            selected,
                            selectable_flags,
                            (0, 0),
                        ):
                            if option != current_option:
                                rule.salvage_option = option
                                changed = True
                finally:
                    PyImGui.end_combo()
        finally:
            self._draw_helper_tooltip("salvage_option")
            PyImGui.pop_item_width()
        return changed

    def _draw_salvage_upgrade_target_editor(self, index: int, rule: SalvageRule) -> bool:
        changed = False
        selected_identifiers = _dedupe_identifiers(getattr(rule, "target_weapon_mod_identifiers", []))
        selected_threshold_rules = _normalize_weapon_mod_threshold_rules(
            getattr(rule, "target_weapon_mod_thresholds", [])
        )
        selected_variant_rules = _normalize_weapon_mod_variant_rules(getattr(rule, "target_weapon_mod_variants", []))
        selected_variant_threshold_rules = _normalize_weapon_mod_variant_threshold_rules(
            getattr(rule, "target_weapon_mod_variant_thresholds", [])
        )

        def build_target_choice_keys() -> list[str]:
            choice_keys = _dedupe_identifiers(
                [_make_weapon_mod_identifier_choice_key(identifier) for identifier in selected_identifiers]
                + [
                    _make_weapon_mod_identifier_choice_key(str(threshold_rule.identifier or "").strip())
                    for threshold_rule in selected_threshold_rules
                ]
                + [_weapon_mod_variant_rule_choice_key(variant_rule) for variant_rule in selected_variant_rules]
                + [
                    _weapon_mod_variant_rule_choice_key(threshold_rule)
                    for threshold_rule in selected_variant_threshold_rules
                ]
            )
            return [choice_key for choice_key in choice_keys if choice_key]

        target_choice_keys = build_target_choice_keys()
        selected_option = _resolve_salvage_session_option(rule.salvage_option)
        is_auto_upgrade_option = _is_auto_exact_upgrade_salvage_option(rule.salvage_option)

        self._draw_secondary_text(
            "Targets matching items for Merchant Rules salvage planning/protection. "
            "Run Salvage extracts only when this upgrade choice can be selected safely."
        )
        if is_auto_upgrade_option and not target_choice_keys:
            self._draw_secondary_text("Specific upgrade needs at least one specific upgrade target.")
        elif selected_option not in SALVAGE_UPGRADE_OPTIONS and not is_auto_upgrade_option and target_choice_keys:
            self._draw_colored_text(
                "Specific-upgrade targets require prefix, suffix, or inscription salvage. "
                "Run Salvage skips these targets while this rule uses default/material salvage.",
                UI_COLOR_WARNING_SOFT,
            )
        elif (
            (selected_option in SALVAGE_UPGRADE_OPTIONS or is_auto_upgrade_option)
            and not self._has_salvage_upgrade_session_support()
        ):
            self._draw_secondary_text(
                "This extraction mode is not available right now. "
                "Matching items stay protected and Run Salvage skips extraction."
            )

        self._draw_subsection_label(f"Target Entries: {len(target_choice_keys)}")
        self._draw_helper_tooltip("salvage_specific_upgrade_targets")

        if self._draw_confirm_destructive_button(f"Clear Specific Upgrade Targets##merchant_rules_salvage_upgrade_clear_{index}"):
            if self._set_salvage_rule_weapon_mod_identifiers(rule, []):
                changed = True
                selected_identifiers = []
            if self._set_salvage_rule_weapon_mod_thresholds(rule, []):
                changed = True
                selected_threshold_rules = []
            if self._set_salvage_rule_weapon_mod_variants(rule, []):
                changed = True
                selected_variant_rules = []
            if self._set_salvage_rule_weapon_mod_variant_thresholds(rule, []):
                changed = True
                selected_variant_threshold_rules = []
            target_choice_keys = build_target_choice_keys()

        if self._draw_selected_weapon_mod_protections(
            "salvage_upgrade_targets",
            index,
            rule,
            selected_identifiers=selected_identifiers,
            threshold_rules=selected_threshold_rules,
            identifier_setter=self._set_salvage_rule_weapon_mod_identifiers,
            threshold_setter=self._set_salvage_rule_weapon_mod_thresholds,
            selected_variants=selected_variant_rules,
            variant_threshold_rules=selected_variant_threshold_rules,
            variant_setter=self._set_salvage_rule_weapon_mod_variants,
            variant_threshold_setter=self._set_salvage_rule_weapon_mod_variant_thresholds,
            empty_text="No specific upgrade targets selected yet.",
            value_column_label="Target If",
        ):
            changed = True
            selected_identifiers = list(rule.target_weapon_mod_identifiers)
            selected_threshold_rules = list(rule.target_weapon_mod_thresholds)
            selected_variant_rules = list(rule.target_weapon_mod_variants)
            selected_variant_threshold_rules = list(rule.target_weapon_mod_variant_thresholds)
            target_choice_keys = build_target_choice_keys()

        search_text = self.salvage_weapon_mod_search_cache.get(index, "")
        updated_search_text = PyImGui.input_text(
            f"Search Specific Upgrades##merchant_rules_salvage_upgrade_search_{index}",
            search_text,
        )
        self._draw_hover_tooltip("Search by upgrade name or identifier.")
        if updated_search_text != search_text:
            self.salvage_weapon_mod_search_cache[index] = updated_search_text

        picked_identifier, visible_identifiers = self._draw_identifier_search_results(
            f"merchant_rules_salvage_upgrade_results_{index}",
            self.salvage_weapon_mod_search_cache.get(index, ""),
            self.weapon_mod_entries,
        )
        addable_identifiers = [identifier for identifier in visible_identifiers if identifier not in target_choice_keys]
        if self._draw_add_all_matches_button(
            f"merchant_rules_salvage_upgrade_results_add_all_{index}",
            len(visible_identifiers),
            len(addable_identifiers),
        ):
            next_identifiers = list(selected_identifiers)
            next_variants = list(selected_variant_rules)
            for choice_key in addable_identifiers:
                kind, identifier, target_item_type, component_kind = _parse_weapon_mod_choice_key(choice_key)
                if kind == WEAPON_MOD_CHOICE_KIND_VARIANT:
                    next_variants.append(
                        WeaponModVariantRule(
                            identifier=identifier,
                            target_item_type=target_item_type,
                            component_kind=component_kind,
                        )
                    )
                elif kind == WEAPON_MOD_CHOICE_KIND_GENERIC:
                    next_identifiers.append(identifier)
            if self._set_salvage_rule_weapon_mod_identifiers(rule, next_identifiers):
                changed = True
                selected_identifiers = list(rule.target_weapon_mod_identifiers)
            if self._set_salvage_rule_weapon_mod_variants(rule, next_variants):
                changed = True
                selected_variant_rules = list(rule.target_weapon_mod_variants)
            target_choice_keys = build_target_choice_keys()

        if picked_identifier:
            if picked_identifier not in target_choice_keys:
                kind, identifier, target_item_type, component_kind = _parse_weapon_mod_choice_key(picked_identifier)
                if kind == WEAPON_MOD_CHOICE_KIND_VARIANT:
                    next_variants = list(selected_variant_rules)
                    next_variants.append(
                        WeaponModVariantRule(
                            identifier=identifier,
                            target_item_type=target_item_type,
                            component_kind=component_kind,
                        )
                    )
                    if self._set_salvage_rule_weapon_mod_variants(rule, next_variants):
                        changed = True
                        selected_variant_rules = list(rule.target_weapon_mod_variants)
                elif kind == WEAPON_MOD_CHOICE_KIND_GENERIC:
                    if self._set_salvage_rule_weapon_mod_identifiers(rule, selected_identifiers + [identifier]):
                        changed = True
                        selected_identifiers = list(rule.target_weapon_mod_identifiers)
            self.salvage_weapon_mod_search_cache[index] = self._get_weapon_mod_choice_label(picked_identifier)

        return changed

    def _draw_salvage_rule_editor(self, index: int, rule: SalvageRule, settings: SalvageSettings) -> bool:
        changed = False
        summary_text, ready = self._get_salvage_rule_summary(rule)
        state_label, state_color = self._get_rule_state_badge(enabled=bool(rule.enabled), ready=ready)
        type_label, type_color = "Salvage", UI_COLOR_WARNING

        opened, enabled, _header_clicked, updated_rule_name, renamed = self._draw_rule_header_row(
            f"salvage_rule_header_{index}",
            f"{self._get_rule_display_label(rule, 'Salvage Rule')}###salvage_rule_{index}",
            type_label,
            type_color,
            summary_text,
            state_label,
            state_color,
            f"Enabled##salvage_enabled_{index}",
            bool(rule.enabled),
            rename_edit_key=f"salvage_rule_name_{index}",
            rule_name=rule.name,
        )
        if enabled != rule.enabled:
            rule.enabled = enabled
            changed = True
        if renamed:
            rule.name = updated_rule_name
            changed = True

        if not opened:
            return changed

        self._draw_section_heading("Basic")
        changed = self._draw_salvage_option_combo(index, rule) or changed
        configured_option = _normalize_salvage_option(rule.salvage_option)
        selected_option = _resolve_salvage_session_option(rule.salvage_option)
        is_auto_upgrade_option = _is_auto_exact_upgrade_salvage_option(rule.salvage_option)
        if selected_option in SALVAGE_UPGRADE_OPTIONS or is_auto_upgrade_option:
            if self._has_salvage_upgrade_session_support():
                if is_auto_upgrade_option:
                    self._draw_secondary_text(
                        "Infers prefix, suffix, or inscription from the matched specific upgrade target."
                    )
                else:
                    self._draw_secondary_text("Uses a Perfect, Expert, or Superior Salvage Kit when available.")
            else:
                self._draw_secondary_text(
                    "Prefix, suffix, and inscription extraction require deterministic slot targeting. "
                    "Matching items stay protected, but Run Salvage skips them safely."
                )
        else:
            self._draw_secondary_text("Materials use normal Salvage Kits.")

        PyImGui.spacing()
        self._draw_subsection_heading("Rarities")
        changed = self._draw_salvage_rarity_toggles(rule, f"rule_{index}") or changed

        PyImGui.spacing()
        self._draw_subsection_heading("Categories")
        changed = self._draw_salvage_category_toggles(rule, f"rule_{index}") or changed
        if bool(rule.categories.get(SALVAGE_CATEGORY_OTHER, False)):
            self._draw_warning_text("Other Items may include unexpected salvageable item types. Keep it off unless testing specific drops.")

        PyImGui.separator()
        self._draw_subsection_heading("Specific Upgrade Targets")
        changed = self._draw_salvage_upgrade_target_editor(index, rule) or changed

        PyImGui.separator()
        self._draw_subsection_heading("Specific Items")
        self._draw_subsection_label(f"Selected Items: {len(rule.model_ids)}")
        selected_search_text = self.salvage_model_list_search_cache.get(index, "")
        PyImGui.push_item_width(260)
        updated_selected_search_text = PyImGui.input_text(
            f"Search selected items##merchant_rules_salvage_list_search_{index}",
            selected_search_text,
        )
        PyImGui.pop_item_width()
        if updated_selected_search_text != selected_search_text:
            self.salvage_model_list_search_cache[index] = updated_selected_search_text
            selected_search_text = updated_selected_search_text

        selected_search_active = bool(_normalize_catalog_search_text(selected_search_text))
        visible_selected_model_ids: set[int] | None = None
        if selected_search_active:
            visible_selected_model_ids = {
                int(model_id)
                for model_id in rule.model_ids
                if self._model_id_matches_item_search_text(model_id, selected_search_text)
            }
        removed_model_id = self._draw_selected_model_ids(
            f"salvage_models_{index}",
            index,
            rule.model_ids,
            display_model_ids=visible_selected_model_ids,
            filtered_empty_text="No selected salvage items match this search.",
            show_exact_protection_badge=True,
        )
        if removed_model_id > 0:
            changed = self._set_salvage_rule_model_ids(
                rule,
                [model_id for model_id in rule.model_ids if int(model_id) != int(removed_model_id)],
            ) or changed

        if self._draw_confirm_destructive_button(f"Clear Models##merchant_rules_salvage_clear_models_{index}"):
            changed = self._set_salvage_rule_model_ids(rule, []) or changed

        if selected_search_active:
            self._draw_secondary_text(
                f"{len(visible_selected_model_ids or set())} of {len(rule.model_ids)} selected item(s) shown.",
                wrapped=False,
            )

        PyImGui.spacing()
        self._draw_subsection_heading("Add Items")
        search_text = self.salvage_model_search_cache.get(index, "")
        updated_search_text = PyImGui.input_text(f"Search items to salvage##merchant_rules_salvage_search_{index}", search_text)
        if updated_search_text != search_text:
            self.salvage_model_search_cache[index] = updated_search_text

        existing_salvage_model_ids = {int(model_id) for model_id in rule.model_ids}
        picked_model_id, visible_model_ids = self._draw_search_results(
            f"merchant_rules_salvage_search_results_{index}",
            self.salvage_model_search_cache.get(index, ""),
            existing_salvage_model_ids,
            "Already selected",
        )
        addable_model_ids = [model_id for model_id in visible_model_ids if model_id not in rule.model_ids]
        if self._draw_add_all_matches_button(
            f"merchant_rules_salvage_search_results_add_all_{index}",
            len(visible_model_ids),
            len(addable_model_ids),
        ):
            changed = self._set_salvage_rule_model_ids(rule, rule.model_ids + addable_model_ids) or changed
        if picked_model_id > 0:
            changed = self._set_salvage_rule_model_ids(rule, rule.model_ids + [picked_model_id]) or changed
            self.salvage_model_search_cache[index] = self._get_model_name(picked_model_id) or str(picked_model_id)

        if PyImGui.collapsing_header(f"Advanced##merchant_rules_salvage_advanced_{index}"):
            current_raw = _format_model_ids(rule.model_ids)
            new_raw, apply_manual_ids = self._draw_manual_model_ids_editor(
                f"salvage_models_{index}",
                current_raw,
            )
            if apply_manual_ids:
                changed = self._set_salvage_rule_model_ids(rule, _parse_model_ids(new_raw)) or changed
            self._draw_secondary_text("Comma-separated model IDs. Apply replaces the exact model list.")

        PyImGui.spacing()
        move_up = False
        move_down = False
        PyImGui.begin_disabled(index <= 0)
        move_up = PyImGui.small_button(f"Move Up##salvage_move_up_{index}")
        PyImGui.end_disabled()
        PyImGui.same_line(0, 8)
        PyImGui.begin_disabled(index >= len(settings.rules) - 1)
        move_down = PyImGui.small_button(f"Move Down##salvage_move_down_{index}")
        PyImGui.end_disabled()
        PyImGui.same_line(0, 8)
        if self._draw_confirm_destructive_button(f"Remove Rule##salvage_remove_{index}"):
            if 0 <= index < len(settings.rules):
                settings.rules.pop(index)
                self.rule_ui_structure_changed = True
                self._refresh_rule_ui_caches()
                changed = True
            PyImGui.tree_pop()
            return changed
        if move_up:
            if self._move_rule_entry(settings.rules, index, -1):
                changed = True
            PyImGui.tree_pop()
            return changed
        if move_down:
            if self._move_rule_entry(settings.rules, index, 1):
                changed = True
            PyImGui.tree_pop()
            return changed

        PyImGui.tree_pop()
        return changed

    def _draw_salvage_workspace(self):
        settings = _normalize_salvage_settings(self.salvage_settings)
        changed = False
        self.rule_ui_structure_changed = False

        self._draw_section_heading("Salvage")
        self._draw_secondary_text(
            "Salvage uses per-rule choices. Protection, customized-item, unidentified non-white, and live salvage checks always run first."
        )

        run_salvage_reason = self._get_action_block_reason("salvage")
        ready_rule_count = self._draw_salvage_status_badges(settings)
        self._draw_secondary_text(self._format_salvage_filter_summary(settings))
        if ready_rule_count <= 0:
            self._draw_warning_text("Add or configure a salvage rule before Salvage can find items.")

        PyImGui.separator()
        self._draw_section_heading("When to Salvage")
        on_inventory_change = PyImGui.checkbox(
            "Salvage selected items on inventory change / pickup##merchant_rules_salvage_on_inventory_change",
            bool(settings.on_inventory_change),
        )
        self._draw_helper_tooltip("salvage_on_inventory_change")
        if on_inventory_change != settings.on_inventory_change:
            settings.on_inventory_change = on_inventory_change
            changed = True
            if settings.on_inventory_change:
                self._request_salvage_rescan()
            else:
                self.salvage_rescan_requested = False
        PyImGui.same_line(0, 8)
        PyImGui.begin_disabled(bool(run_salvage_reason))
        run_salvage_clicked = PyImGui.button("Run Salvage Now##merchant_rules_run_salvage_now")
        PyImGui.end_disabled()

        if run_salvage_reason:
            self._draw_secondary_text(f"Run Salvage Now: {run_salvage_reason}")
        if self.last_salvage_summary:
            self._draw_secondary_text(self.last_salvage_summary)
        if settings.on_inventory_change:
            self._draw_secondary_text("Salvage pauses Inventory Plus while it runs.")

        PyImGui.separator()
        self._draw_section_heading("Rules")
        if PyImGui.button("Add Salvage Rule##merchant_rules_add_salvage_rule"):
            settings.rules.append(_normalize_salvage_rule(SalvageRule()) or SalvageRule())
            self.rule_ui_structure_changed = True
            self._refresh_rule_ui_caches()
            changed = True

        if not settings.rules:
            self._draw_secondary_text("No salvage rules yet.")
        for index, rule in enumerate(list(settings.rules)):
            if index >= len(settings.rules):
                break
            if self._draw_salvage_rule_editor(index, rule, settings):
                changed = True
            if self.rule_ui_structure_changed:
                break
            if index + 1 < len(settings.rules):
                PyImGui.spacing()

        if changed:
            self.salvage_settings = _normalize_salvage_settings(settings)
            self._save_profile()
            self._request_salvage_rescan()
            if self._is_destroy_auto_enabled():
                self._request_instant_destroy_rescan()
            self._mark_preview_dirty("Salvage settings changed. Preview again before destroy execution.")

        if run_salvage_clicked:
            self._queue_salvage_now(auto_triggered=False)

    def _draw_protected_item_type_filter_controls(self):
        category_values = [key for key, _label in DEPOSIT_FILTER_TOP_OPTIONS]
        category_labels = [label for _key, label in DEPOSIT_FILTER_TOP_OPTIONS]
        category = _normalize_item_type_filter_category(self.protected_item_type_filter_category)
        category_index = category_values.index(category) if category in category_values else 0

        PyImGui.push_item_width(210)
        next_category_index = PyImGui.combo(
            "Item Type##merchant_rules_protected_item_type_filter",
            category_index,
            category_labels,
        )
        PyImGui.pop_item_width()
        next_category_index = max(0, min(int(next_category_index), len(category_values) - 1))
        next_category = category_values[next_category_index]
        if next_category != category:
            self.protected_item_type_filter_category = next_category
            self.protected_item_type_filter_subcategory = DEPOSIT_FILTER_ALL
            category = next_category

        if category == DEPOSIT_FILTER_ALL:
            self.protected_item_type_filter_subcategory = DEPOSIT_FILTER_ALL
            return

        subcategory_options = _get_item_type_filter_subcategory_options(category)
        subcategory_values = [key for key, _label in subcategory_options]
        subcategory_labels = [label for _key, label in subcategory_options]
        subcategory = _normalize_item_type_filter_subcategory(
            category,
            self.protected_item_type_filter_subcategory,
        )
        subcategory_index = subcategory_values.index(subcategory) if subcategory in subcategory_values else 0

        PyImGui.same_line(0, 8)
        PyImGui.push_item_width(230)
        next_subcategory_index = PyImGui.combo(
            "Subtype##merchant_rules_protected_item_subtype_filter",
            subcategory_index,
            subcategory_labels,
        )
        PyImGui.pop_item_width()
        next_subcategory_index = max(0, min(int(next_subcategory_index), len(subcategory_values) - 1))
        self.protected_item_type_filter_subcategory = subcategory_values[next_subcategory_index]

